DROP TABLE IF EXISTS `t_daily_quiz`;
CREATE TABLE `t_daily_quiz`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键',
  `quiz_date` date NOT NULL COMMENT '题目日期',
  `quiz_id` bigint NOT NULL COMMENT '关联题目 ID',
  PRIMARY KEY (`id`) USING BTREE,
