-- ----------------------------
-- Table structure for t_daily_recommendation
-- ----------------------------
DROP TABLE IF EXISTS `t_daily_recommendation`;
CREATE TABLE `t_daily_recommendation`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '推荐记录ID',
  `recommend_date` date NOT NULL COMMENT '推荐日期，如2026-04-09',
  `content_id` bigint NOT NULL COMMENT '历史人物ID',
  `created_at` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_recommend_date`(`recommend_date` ASC) USING BTREE,
  INDEX `idx_content`(`content_id` ASC) USING BTREE,
  INDEX `idx_date`(`recommend_date` DESC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 7 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '每日推荐计划表' ROW_FORMAT = Dynamic;

