-- ----------------------------
-- Table structure for t_event
-- ----------------------------
DROP TABLE IF EXISTS `t_event`;
CREATE TABLE `t_event`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键',
  `title` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '事件标题',
  `year` smallint NOT NULL COMMENT '事件发生年份（允许负数表示公元前）',
  `month` tinyint NOT NULL COMMENT '事件发生月份（1-12）',
  `day` tinyint NOT NULL COMMENT '事件发生日期（1-31）',
  `summary` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '事件摘要（列表展示）',
  `content` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '事件详细内容（富文本/多段落）',
  `image_url` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '封面图片 URL',
  `tags` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '标签，逗号分隔（如：近代史,革命）',
  `source` tinyint NOT NULL DEFAULT 1 COMMENT '来源：1=人工录入，2=大模型生成',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_month_day`(`month` ASC, `day` ASC) USING BTREE,
  INDEX `idx_year`(`year` ASC) USING BTREE,
  FULLTEXT INDEX `ft_title_summary`(`title`, `summary`) WITH PARSER `ngram`
) ENGINE = InnoDB AUTO_INCREMENT = 84 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '历史事件表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of t_event
-- ----------------------------
INSERT INTO `t_event` VALUES (69, '周平王东迁洛邑', -770, 4, 9, '周平王姬宜臼为避犬戎之患，将国都从镐京东迁至洛邑，开启东周时代。', '西周灭亡后，太子姬宜臼在诸侯拥立下继位，是为周平王。此时镐京残破，又遭犬戎威胁，平王遂于公元前770年四月九日左右启程东迁。在晋文侯、郑武公、秦襄公等诸侯护卫下，周王室将都城东迁至洛邑，史称东周。东迁后周王室直辖领地大幅缩小，财政困窘，不得不依赖诸侯供给。晋、郑、齐、鲁等国趁机扩张势力，周天子逐渐沦为名义上的共主。这一事件标志着春秋时期的开始，礼乐征伐自天子出的局面被打破，诸侯争霸成为时代主题。东周分为春秋和战国两个阶段，持续五百余年，直至秦统一六国。', 'https://history-study.oss-cn-beijing.aliyuncs.com/event-cover/a2055cf40a99444a92544867f88ab17c.webp', '西周,东周,春秋', 2);
INSERT INTO `t_event` VALUES (70, '北魏孝文帝颁布均田令', 485, 4, 9, '北魏孝文帝拓跋宏颁布均田令，推行按人口分配土地的制度改革，影响深远。', '北魏太和九年，冯太后与孝文帝推行重大改革。此前北方长期战乱，土地荒芜，人口流徙，豪强兼并严重，国家赋税来源枯竭。孝文帝采纳李安世建议，于485年四月正式颁布均田令。规定十五岁以上男子受露田四十亩、桑田二十亩，女子受露田二十亩，奴婢依良民受田，耕牛每头受田三十亩。受田者年老或身死须还田，桑田可世袭。均田制将无主荒地分配给农民，限制豪强兼并，同时与三长制、租调制配合，重建了基层行政与赋役体系。这一制度为北齐、北周、隋、唐所继承，成为中国古代土地制度的基石，促进了北方农业恢复与民族融合。', 'https://history-study.oss-cn-beijing.aliyuncs.com/event-cover/102473b44ee74a5d8fffecbf5c1301bc.webp', '南北朝,北魏', 2);
INSERT INTO `t_event` VALUES (71, '唐玄宗册封杨贵妃', 745, 4, 9, '唐玄宗正式册封杨玉环为贵妃，宠冠后宫，开元盛世由此转向天宝年间。', '天宝四载，唐玄宗李隆基在宫中举行隆重典礼，正式册封寿王妃杨玉环为贵妃，时当四月。此前玄宗已令杨玉环出家为女道士，号太真，再纳入宫中，此时方予名分。杨贵妃通音律、善歌舞，与玄宗志趣相投，玄宗为之倾倒，礼遇等同皇后。杨家因此显贵，兄杨国忠官至宰相，三姐妹皆封国夫人，一门荣宠极矣。玄宗耽于享乐，疏于朝政，将政务委于李林甫、杨国忠。节度使安禄山亦以母事贵妃，内外勾结。天宝年间，均田制瓦解，府兵制崩溃，边将拥兵自重，中央禁军虚弱，盛世表象下危机四伏。十四年后安史之乱爆发，玄宗仓皇西狩，马嵬驿兵变，贵妃缢死，盛唐至此凋零。', 'https://history-study.oss-cn-beijing.aliyuncs.com/event-cover/154ab0fb4d684dc78a66d14e80bc9266.webp', '唐朝', 2);
INSERT INTO `t_event` VALUES (72, '宋神宗诏令编纂《武经七书》', 1078, 4, 9, '宋神宗下诏校定《孙子》等七部兵书，定为武学必修，是为武经七书。', '北宋熙宁年间，王安石变法推行富国强兵之策，武学教育受到重视。熙宁五年始设武学，以兵书教授学生。元丰三年，神宗赵顼下诏命国子监司业朱服、武学博士何去非等校定历代兵书，择其精要编为教材。所收七部为《孙子兵法》《吴子》《司马法》《六韬》《尉缭子》《三略》《李卫公问对》，涵盖先秦至唐代的军事思想精华。校定工作历时数年，于元丰年间完成镂版刊行。《武经七书》成为中国古代第一部官定军事教科书，为宋代以降武举考试与武学教育的核心内容，对军事思想传承影响深远。其版本流传日本、朝鲜，亦为东亚兵学经典。', 'https://history-study.oss-cn-beijing.aliyuncs.com/event-cover/7bd6b488fac34f6ea39a0d63bc357815.webp', '宋朝', 2);
INSERT INTO `t_event` VALUES (73, '清道光帝命林则徐赴广东禁烟', 1839, 4, 9, '道光帝任命林则徐为钦差大臣，驰赴广东查禁鸦片，虎门销烟一触即发。', '道光年间，鸦片泛滥成灾，白银外流，军民身心俱损，朝野禁烟呼声高涨。道光十八年，鸿胪寺卿黄爵滋奏请严禁鸦片，林则徐力主禁烟，奏折称此祸不除，数十年后中原几无可以御敌之兵。道光帝深以为然，于1838年底连续召见林则徐八次，授以钦差大臣关防，令驰赴广东查办海口事件，节制水师，全权办理禁烟。1839年1月林则徐离京南下，4月初抵达广州，即日传谕外商缴烟。英商顽抗，林则徐断然封舱停市，围守商馆，迫令具结。至五月，收缴鸦片二万余箱，于虎门海滩当众销毁。此举震动中外，成为第一次鸦片战争的导火索，亦开启中国近代反侵略斗争之序幕。', 'https://history-study.oss-cn-beijing.aliyuncs.com/event-cover/4e37f53e3ccf41029f6f0f687d5437c2.webp', '清朝,晚清', 2);
INSERT INTO `t_event` VALUES (74, '周成王封弟叔虞于唐', -1035, 4, 10, '周成王以桐叶为圭戏封弟叔虞，史佚促成正式分封，建立晋国雏形。', '桐叶封弟是中国古代著名的政治典故，见于《史记·晋世家》等文献记载。周成王姬诵即位初年，年幼时与胞弟叔虞在宫中玩耍，成王随手摘下一片梧桐树叶，削成圭形递给叔虞，戏言以此封他。史官史佚在场，当即请求择日正式册封。成王表示不过是玩笑，史佚则严肃进言：天子无戏言，言则史书之、礼成之、乐歌之。成王遂从之，正式将唐地封给叔虞，史称唐叔虞。唐地位于黄河、汾河之间，原为夏墟，有陶唐氏之遗民。叔虞受封后，励精图治，整饬政务，安抚旧民，推行周礼，使唐地逐渐安定繁荣。叔虞死后，其子燮父继位，因境内有晋水，遂改国号为晋，是为晋侯。桐叶封弟一事体现了西周初年分封制度的严肃性，以及史官对王权的制约作用，也成为后世强调君主慎言的重要典故。晋国后来发展为春秋五霸之一，在中原政治格局中扮演关键角色，其历史渊源正可追溯至此时的分封。', 'https://history-study.oss-cn-beijing.aliyuncs.com/event&people/adc65c9ad1fb4b61a4d88c2b31d0bb3a.webp', '西周,分封制,晋国,周成王', 2);
INSERT INTO `t_event` VALUES (75, '汉明帝始建辟雍', 59, 4, 10, '汉明帝于洛阳南郊建辟雍，行大射礼与养老礼，重振儒家礼乐教化。', '东汉永平二年，汉明帝刘庄为彰显儒家治国理念，下诏在洛阳南郊修建辟雍。辟雍为古代天子所设大学，取四周有水、形如璧环之意，象征教化流行如水之无阻。此工程历时数年，至永平十年正式落成。辟雍建成后，明帝亲临举行大射礼与养老礼，召集郡国所举明经之士及公卿子弟入学肄业，并邀请三老五更入宫受养，以示范天下尊老重学之风。明帝本人精通儒学，曾多次亲临辟雍讲经，与诸儒论难，使东汉初年儒学复兴达到新的高度。辟雍之制上承西周，下启后世国子监，是中国古代高等教育体系的重要环节。此次建置不仅完善了东汉的礼制建设，更通过教化手段巩固了中央集权，缓和了光武中兴以来豪强势力膨胀带来的社会矛盾，为明章之治的文化繁荣奠定基础。洛阳辟雍遗址后经考古发掘，其圆形建筑基址与史籍记载相互印证，成为研究汉代礼制建筑的珍贵实物资料。', 'https://history-study.oss-cn-beijing.aliyuncs.com/event&people/fee422f02f8f4f439f2cbddf3e2b74c2.webp', '东汉,汉朝,汉明帝,儒学,礼制', 2);
INSERT INTO `t_event` VALUES (76, '唐玄宗赐号三藏法师', 745, 4, 10, '唐玄宗于长安亲自为玄奘弟子义净赐号三藏法师，表彰其西行译经之功。', '唐天宝四载，唐玄宗李隆基在长安大明宫亲自为高僧义净赐号三藏法师。义净俗姓张，字文明，齐州人，是继玄奘之后又一位西行求法的高僧。他于高宗咸亨二年从广州乘船出发，经海路抵达印度，在那烂陀寺留学十余年，游历三十余国，于武周证圣元年携梵本经论近四百部返回洛阳。义净回国后，先后在长安、洛阳主持译场，译出《金光明最胜王经》《大孔雀咒王经》等经律六十一部，二百三十九卷，并撰有《南海寄归内法传》《大唐西域求法高僧传》等重要著述，记录当时印度与南海诸国的佛教状况及社会风俗。玄宗赐号之时，义净已年逾古稀，仍主持佛经翻译工作。此次赐号不仅是对义净个人求法译经功绩的肯定，更体现了盛唐时期皇室对佛教的支持与利用。玄宗前期虽尊崇道教，但对佛教名僧仍给予优礼，通过宗教政策调和三教关系，维护统治合法性。义净所译经典与著述，为研究七世纪印度、东南亚历史地理及中印文化交流提供了珍贵文献，其海路求法的经历也拓展了中原与南海的交通路线。', 'https://history-study.oss-cn-beijing.aliyuncs.com/event&people/83ee707a86f94e5fa926d9b18f420dbf.webp', '唐朝,唐玄宗,佛教,义净,玄奘', 2);
INSERT INTO `t_event` VALUES (77, '宋仁宗诏修《唐书》', 1044, 4, 10, '宋仁宗命宋祁、欧阳修等重撰唐史，至嘉祐五年完成，是为《新唐书》。', '宋庆历四年，宋仁宗赵祯因不满五代后晋所修《旧唐书》繁冗失实，下诏重修唐史。此前《旧唐书》成书仓促，史料剪裁不当，且历经战乱，版本亦有残缺。仁宗以翰林学士宋祁为刊修官，起居舍人欧阳修同修，后又增派吕夏卿、刘羲叟、梅尧臣等人参与编撰。此次修史历时十七年，至嘉祐五年方告完成，共二百二十五卷，包括本纪十卷、志五十卷、表十五卷、列传一百五十卷，是为《新唐书》。欧阳修主持撰写本纪、志、表，宋祁负责列传，二人书法各异，欧文笔法严谨简洁，宋祁偏好古奥艰深，故《新唐书》文辞较《旧唐书》更为简练，但亦有过于追求简古而失之晦涩之处。书中新增《仪卫志》《选举志》《兵志》等，补《旧唐书》无志之缺；创设《宰相表》《方镇表》《宗室世系表》，便于查考。宋仁宗亲为之序，称此书可垂鉴戒、示法程。《新唐书》与《旧唐书》并行于世，为研究唐代历史的基本文献，其编纂过程也反映了北宋士大夫以史为鉴、振兴儒学的文化自觉，以及仁宗朝文治政策的具体实施。', 'https://history-study.oss-cn-beijing.aliyuncs.com/event&people/78b7ee316b784c128105f763692a8045.webp', '宋朝,北宋,宋仁宗,欧阳修,唐书', 2);
INSERT INTO `t_event` VALUES (78, '清康熙帝南巡阅河', 1707, 4, 10, '康熙帝第六次南巡抵达扬州，阅视高家堰、洪泽湖堤工，指示河务方略。', '清康熙四十六年三月，康熙帝玄烨开启第六次南巡之旅，于四月初十日抵达扬州。此次南巡主要目的为巡视河工，解决黄河、淮河、运河交汇区域的连年水患。康熙帝此前五次南巡均重视河务，亲赴工地勘察，听取河臣汇报。此次抵达扬州后，即召见河道总督张鹏翮、两江总督邵穆布等，详细询问高家堰堤防、洪泽湖蓄水及清口疏浚情况，并乘舟亲阅河势。高家堰为淮河下游关键堤防，关系洪泽湖蓄水宣泄及运河通航，康熙帝指示须加固堤身、增筑子堰，以保障里下河地区农田安全。同时，他注意到黄河泥沙淤积导致清口不畅，要求引淮河水冲刷黄河海口，以减淤滞。康熙帝在扬州期间，还减免当地钱粮，接见地方耆老，题诗瘦西湖畔，示以君臣同乐之意。此次南巡所定河务方略，后经张鹏翮等实施，取得一定成效，淮河下游水患有所缓解。康熙帝六巡江南，其勤政爱民、注重实政的形象深入民心，也成为清代前期政治清明的象征，但河工耗费巨大，后期积弊渐生，至乾隆朝更趋严重。', 'https://history-study.oss-cn-beijing.aliyuncs.com/event&people/97830394c95c4b46a25d4e57a606c153.webp', '清朝,康熙,南巡,河工,扬州', 2);
INSERT INTO `t_event` VALUES (79, '周平王东迁洛邑', -770, 4, 15, '周平王为避犬戎之患，将都城东迁至洛邑，东周开始，礼乐征伐自诸侯出。', '公元前770年，周平王宜臼在郑、秦、晋等诸侯的护卫下，将周朝都城从镐京东迁至洛邑，史称平王东迁。此前，周幽王因宠爱褒姒，废黜申后与太子宜臼，改立褒姒之子伯服为太子。申侯联合缯国与犬戎进攻镐京，幽王被杀，西周灭亡。宜臼继位后，面对镐京残破、犬戎威胁的困境，决定东迁。洛邑地处中原腹地，有伊洛之险，且为周公营建的东都，基础尚存。东迁后，周王室势力大衰，直辖领土锐减，财政困窘，不得不依赖诸侯供给。诸侯势力趁机崛起，郑、齐、晋、楚等国相继称霸，礼乐征伐之权下移，中国历史进入春秋时期。平王东迁标志着西周时代的终结和东周时代的开端，是周朝由盛转衰的关键节点，也为此后五百余年的诸侯争霸局面奠定了基础。', 'https://history-study.oss-cn-beijing.aliyuncs.com/event&people/1bb366d86b214cf1a06b9451f9fe4999.webp', '东周,春秋,周朝,政治', 2);
INSERT INTO `t_event` VALUES (80, '明成祖迁都北京', 1421, 4, 15, '明成祖正式迁都北京，改南京为留都，北京成为明朝政治中心，奠定此后五百年帝都格局。', '永乐十九年四月初，明成祖朱棣正式颁布迁都诏书，以北京为京师，改金陵为南京，作为留都。迁都之举始于永乐元年，朱棣以北平为兴龙之地，决意营建新都。永乐四年诏建北京宫殿，永乐十五年全面开工，征调全国工匠民夫数十万，历时十四年建成紫禁城、太庙、社稷坛等核心建筑。永乐十八年十一月，诏告天下迁都，十九年正月初一，在奉天殿举行大朝会，正式确立北京的首都地位。迁都北京具有深远的战略考量：其一，北元势力尚存，天子守国门可震慑蒙古；其二，朱棣根基在北方，远离南京建文旧势力；其三，疏通运河，漕运江南财赋以实京师。然而迁都初期阻力重重，永乐十九年四月初，奉天、华盖、谨身三殿遭雷击焚毁，群臣借机谏言还都南京，成祖震怒，主事大臣萧仪被处死，迁都之议暂息。此后明朝以北京为京师直至灭亡，北京由此成为连续五百余年的中国政治中心，其城市格局与建筑遗存影响至今。', 'https://history-study.oss-cn-beijing.aliyuncs.com/event&people/5dd5c93bb0024236a3805ac7942c2720.webp', '明朝,永乐,政治,建筑', 2);
INSERT INTO `t_event` VALUES (81, '清圣祖削夺吴三桂王爵', 1674, 4, 15, '康熙帝下诏削夺吴三桂王爵，举兵讨伐，三藩之乱全面爆发，清廷与吴三桂政权进入战争状...', '康熙十三年四月，清圣祖玄烨下诏削夺平西王吴三桂爵位，剥夺其官职，宣布讨伐，标志着三藩之乱进入全面战争阶段。三藩之乱的根源在于清初为镇压南明势力而分封的汉族藩王势力坐大。吴三桂镇守云南，兼辖贵州，拥兵自重，岁糜巨饷，且与清廷互生猜忌。康熙十二年，朝廷议撤藩，吴三桂、耿精忠、尚之信相继请撤以试探，康熙帝力排众议，果断允准。吴三桂本意以退为进，不料弄假成真，遂于康熙十二年十一月杀云南巡抚朱国治，自称天下都招讨兵马大元帅，蓄发易服，以复明为号召起兵。初期叛军势如破竹，贵州、四川、湖南、广西相继响应，耿精忠、尚之信、孙延龄等先后反叛，战火遍及半壁江山，清廷震动。康熙帝沉着应对，采取分化瓦解策略，重点打击吴三桂，对耿、尚则招抚怀柔。削爵诏书颁布后，清军逐渐稳住阵脚，双方在湖南对峙。此后八年，战争持续，直至康熙二十年吴三桂之孙吴世璠自杀，三藩平定。此役对清朝统治影响深远，既消除了地方割据势力，强化了中央集权，也暴露出八旗战力衰退，促使清廷重用绿营汉军。', 'https://history-study.oss-cn-beijing.aliyuncs.com/event&people/1ff8ce1f75a748e699632f405ccef87a.webp', '清朝,康熙,三藩之乱,军事', 2);
INSERT INTO `t_event` VALUES (82, '北魏太武帝诛崔浩', 450, 4, 15, '北魏太武帝拓跋焘以修史暴露国恶为由，诛杀重臣崔浩及其姻亲，国史之狱震动朝野，士族...', '太平真君十一年四月，北魏太武帝拓跋焘下令诛杀司徒崔浩，并夷灭其族，牵连范阳卢氏、太原郭氏、河东柳氏等北方大族，史称国史之狱。崔浩历仕北魏道武、明元、太武三帝，为太武帝宠臣，参与军国大谋，官至司徒，奉诏修撰《国书》。崔浩主张恢复士族特权，排抑鲜卑贵族，又信奉天师道，与太子拓跋晃不睦，朝中积怨已深。崔浩主持修史时，将《国书》刻石立于郊祀坛东，以示直笔，内容涉及拓跋氏早期隐晦事迹，鲜卑贵族借机发难，指控崔浩暴露国恶。太武帝震怒，收捕崔浩，囚禁于城南木笼，施以苦辱。四月，崔浩被诛，时年七十，其宗族及姻亲范阳卢氏、太原郭氏、河东柳氏等皆遭连坐，死者数百人，北方士族元气大伤。崔浩之死反映了北魏胡汉矛盾的尖锐，太武帝晚年猜忌暴虐，太子拓跋晃忧惧而死，朝局动荡。此狱后，北魏士族势力受挫，鲜卑贵族气焰高涨，直至孝文帝改革方有转机。崔浩所修《国书》亦遭禁毁，今仅存残篇，为研究北魏早期历史的重要遗憾。', 'https://history-study.oss-cn-beijing.aliyuncs.com/event&people/aae5b2683de24f1daf41c9ad669ed66f.webp', '南北朝,北魏,政治,文化', 2);
INSERT INTO `t_event` VALUES (83, '宋仁宗诏令州县立学', 1044, 4, 15, '宋仁宗下诏令天下州县皆立学，赐学田以赡士，科举取士与学校教育结合，宋代教育制度由...', '庆历四年四月，宋仁宗赵祯采纳参知政事范仲淹等人建议，颁布诏书，令天下州县皆立学校，并赐学田以资经费，史称庆历兴学。此举是范仲淹主持的庆历新政重要内容，旨在改革科举、培育人才。此前，宋代虽有中央官学国子监、太学，地方学校却兴废无常，士人多寄读于山林书院或私家学舍，教育普及程度有限。范仲淹认为科举专以辞赋取士，不足以为国家得人才，主张兴学校、敦名节。诏书规定：州县学由守令主持，选拔属官为教授，士须在学校习业一定时日方许应举；同时赐给学田，以租入充学费。诏令下达后，各地纷纷响应，建学之风大兴，如湖州州学、苏州州学皆建于此时，延聘名师，生徒常数百人。虽因庆历新政夭折，兴学措施部分废止，但州县立学的方向得以延续，至熙宁、崇宁年间，王安石、蔡京相继扩大学制，太学三舍法、州县学舍法次第推行，形成遍布全国的学校网络。宋代教育的普及与科举的开放相互促进，造就了文人政治的格局，对中国古代社会阶层流动与文化传承影响深远。', 'https://history-study.oss-cn-beijing.aliyuncs.com/event&people/0c694073f4704508a5dec9cc93fd0470.webp', '宋朝,北宋,庆历,教育', 2);

-- ----------------------------
-- Table structure for t_event_relation
-- ----------------------------
DROP TABLE IF EXISTS `t_event_relation`;
CREATE TABLE `t_event_relation`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键',
  `event_id` bigint NOT NULL COMMENT '源事件 ID',
  `related_id` bigint NOT NULL COMMENT '关联事件 ID',
  `sort_order` int NOT NULL DEFAULT 0 COMMENT '排序权重',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_event_related`(`event_id` ASC, `related_id` ASC) USING BTREE,
  INDEX `idx_event_id`(`event_id` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 121 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '事件关联表（延伸阅读）' ROW_FORMAT = Dynamic;

