INSERT INTO `t_historical_figure` VALUES (41, '沈括', '北宋科学家、政治家、外交家', '1031年', '1095年', '北宋', '杭州钱塘（今浙江省杭州市）', 'https://history-study.oss-cn-beijing.aliyuncs.com/event&people/377ddd21a48443ba8d6ea20692e485e4.webp', '沈括，字存中，号梦溪丈人，北宋时期杰出的科学家、政治家和外交家，被誉为\"中国科学史上的坐标\"。他出身于官宦世家，父亲沈周曾任地方官吏，母亲许氏知书达理，良好的家庭教育为沈括日后的学术成就奠定了坚实基础。\n\n沈括自幼聪颖好学，博览群书，对天文、地理、历法、数学、物理、化学、生物、医药、文学、史学、音乐、美术等领域均有深入研究。嘉祐八年（1063年），沈括进士及第，步入仕途。熙宁年间，他积极参与王安石变法，担任三司使、翰林学士等职，在财政改革、军事建设等方面发挥了重要作用。熙宁七年（1074年），沈括出使辽国，面对辽方提出的领土要求，他据理力争，以详实的地理知识和历史文献为依据，成功维护了宋朝的领土主权，展现了卓越的外交才能。\n\n元丰三年（1080年），沈括出任鄜延路经略安抚使，知延州，负责西北边防事务。他在任期间整顿军备，加强防御，多次击退西夏军队的进攻。然而，元丰五年（1082年），因永乐城之战的失利，沈括受到牵连，被贬为均州团练副使，后徙秀州。这段政治挫折使沈括将更多精力投入学术研究。晚年，他隐居润州（今江苏镇江）梦溪园，潜心著述，完成了科学巨著《梦溪笔谈》。\n\n《梦溪笔谈》是沈括一生学术成就的集大成之作，全书共三十卷，内容涉及天文、历法、数学、物理、化学、地理、地质、生物、医药、农学、工程技术、文学、史学、音乐、美术等多个领域，记载了北宋时期的科技成就和社会状况，保存了大量珍贵的历史资料。在天文学方面，沈括改进了浑仪、浮漏和影表等天文仪器，提出了\"十二气历\"的历法改革方案，比欧洲类似的历法早了八百多年。在数学方面，他创立了\"隙积术\"和\"会圆术\"，在高阶等差级数求和和圆弧长度计算方面取得了重要突破。在物理学方面，他发现了地磁偏角的存在，比欧洲早四百多年；研究了小孔成像、凹面镜成像等光学现象；论述了共振现象和声音的传播规律。在地质学方面，他提出了海陆变迁、流水侵蚀等地质学理论，并根据化石推断古代地理环境。在地理学方面，他绘制了《天下州县图》，采用了比例尺和方位标注等科学方法。\n\n沈括的科学成就不仅在当时处于世界领先水平，而且对后世产生了深远影响。英国科学史家李约瑟在《中国科学技术史》中高度评价沈括，称他是\"中国整部科学史中最卓越的人物\"。沈括的治学方法和科学精神，体现了中国古代知识分子的理性探索精神和对自然规律的执着追求。他的著作不仅是研究北宋科技史的重要文献，也是中华文明宝库中的璀璨明珠。', '梦溪笔谈,长兴集,苏沈良方,良方,浑仪议,浮漏议,景表议,天下州县图', '2026-04-09 16:24:04', '2026-04-09 16:24:04');
INSERT INTO `t_historical_figure` VALUES (42, '张居正', '明代政治家、改革家，万历首辅', '1525年5月24日', '1582年7月9日', '明朝', '湖广江陵（今湖北省荆州市）', 'https://history-study.oss-cn-beijing.aliyuncs.com/event&people/512322370e574339ac5fbc2d616c980c.webp', '张居正，字叔大，号太岳，湖广江陵人，明代杰出的政治家、改革家。他出身寒微，自幼聪颖过人，十二岁中秀才，十六岁中举人，二十三岁中进士，选庶吉士，授翰林院编修，由此步入仕途。张居正历经嘉靖、隆庆、万历三朝，在复杂的政治斗争中逐渐崛起，最终于隆庆六年（1572年）以首辅身份执掌朝政，成为明代最有权势的内阁首辅之一。\n\n张居正执政期间，面对明朝中叶以来积弊深重的局面，推行了一系列大刀阔斧的改革，史称\"万历新政\"。在政治上，他创制\"考成法\"，严格考核各级官吏，整顿吏治，提高行政效率，使\"虽万里外，朝下而夕奉行\"。在经济上，他推行\"一条鞭法\"，将赋役合并，计亩征银，简化了税制，减轻了农民负担，增加了国家财政收入。同时，他清丈全国土地，打击豪强隐田，使国家掌握的田亩数大幅增加。在军事上，他重用戚继光、李成梁等名将，整顿边防，巩固了北方防务；任用潘季驯治理黄河、淮河，成效显著。在文化上，他整顿学风，压制空谈，提倡务实。\n\n张居正的改革使明朝出现了短暂的中兴局面，国库充盈，边防巩固，社会相对稳定。史载万历初年\"太仓粟可支十年，太仆寺积金至四百余万\"，足见改革成效之显著。然而，张居正的改革也触动了大地主、大官僚的利益，加之他执政期间权势过重，威福自专，引起朝野不满。万历十年（1582年）张居正病逝，谥号文忠。不久，神宗亲政后对其展开清算，抄没其家，子弟或死或戍，改革措施大多废止，明朝也由此走向衰落。\n\n张居正的历史地位和评价历来复杂。他既是挽救明朝危局的能臣，也是专权跋扈的权相；既是厉行改革的实干家，也是生活奢靡、教子不严的凡人。清代学者梁启超称其为\"明代唯一的大政治家\"，而《明史》则批评他\"威柄之操，几于震主\"。无论如何，张居正以其非凡的政治才能和坚定的改革意志，在中国历史上留下了浓墨重彩的一笔，其改革思想和实践对后世产生了深远影响。', '张太岳集,书经直解,帝鉴图说,张居正奏疏集', '2026-04-09 16:24:38', '2026-04-09 16:24:38');
INSERT INTO `t_historical_figure` VALUES (43, '王阳明', '明代哲学家、军事家、教育家，心学集大成者', '1472年10月31日', '1529年1月9日', '明朝', '浙江余姚（今浙江省宁波市余姚市）', 'https://history-study.oss-cn-beijing.aliyuncs.com/event&people/d3f6877bc7d8467cae6247101f5dfde7.webp', '王阳明，原名王守仁，字伯安，号阳明，世称阳明先生，明代最具影响力的思想家之一。他出身于书香门第，父亲王华是成化十七年状元，官至南京吏部尚书。王阳明自幼聪颖过人，十二岁立志\"读书学圣贤\"，展现出非凡的气度与抱负。\n\n弘治十二年（1499年），王阳明考中进士，步入仕途。然而，他的政治生涯并非一帆风顺。正德元年（1506年），因得罪宦官刘瑾，被廷杖四十，贬谪至贵州龙场驿任驿丞。这次贬谪成为王阳明人生的重要转折点。在龙场这偏僻荒凉之地，他历经磨难，日夜反省，终于在某个深夜大悟\"圣人之道，吾性自足\"，创立了影响深远的\"心学\"思想体系，史称\"龙场悟道\"。这一悟道标志着阳明心学的正式诞生，其核心命题\"心即理\"\"知行合一\"\"致良知\"逐渐成形。\n\n正德五年（1510年），刘瑾被诛，王阳明仕途转顺，历任庐陵知县、南京刑部主事、南京太仆寺少卿等职。正德十一年（1516年），他升任都察院右佥都御史，巡抚南赣、汀、漳等地，成功平定当地数十年未靖的民变与匪患。正德十四年（1519年），宁王朱宸濠在南昌起兵叛乱，王阳明当时正奉命前往福建，闻变后立即返师，仅用三十五天便生擒宁王，平定这场震动朝野的叛乱，展现出卓越的军事才能。然而，这一功绩却招致正德皇帝身边佞臣的嫉恨，他一度陷入政治危机，最终凭借智慧与隐忍化解。\n\n嘉靖六年（1527年），广西思恩、田州土司叛乱，两广总督无力平定，朝廷再次起用王阳明。他采用\"抚剿并用\"之策，未费多大兵力便使叛酋归降，并趁机设立学校，教化边民。嘉靖七年（1528年），他在平定八寨、断藤峡等地叛乱后，病重乞归，途中病逝于江西南安府青龙铺，享年五十七岁。临终之际，弟子问他有何遗言，他微微一笑：\"此心光明，亦复何言。\"\n\n王阳明一生著述丰富，其思想经弟子整理成《王文成公全书》，其中《传习录》《大学问》等最为著名。他的心学思想强调\"心外无理\"，认为天理不在事物之中，而在人心之内；提出\"知行合一\"，批判知而不行的虚浮学风；晚年更以\"致良知\"为学问宗旨，主张人人皆有良知，只需向内体认扩充即可成圣。这一思想打破了程朱理学\"格物穷理\"的繁琐路径，将道德修养的主动权归还个人，具有强烈的解放意义。\n\n王阳明的思想不仅深刻影响了明代中后期的学术走向，更远播日本、朝鲜半岛及东南亚，成为东亚思想史的重要遗产。明代后期，阳明心学分化出诸多流派，其中泰州学派更走向平民化，对晚明社会变革产生深远影响。清代虽一度受到压制，但近代以来，梁启超、孙中山、蒋介石等人均深受其影响。当代新儒家牟宗三更将其视为中国哲学的重要传统，与康德哲学展开对话。在军事领域，他的治军理念与心理战术也为后世兵家所推崇。', '传习录,大学问,王文成公全书,朱子晚年定论', '2026-04-09 16:25:29', '2026-04-09 16:25:29');
INSERT INTO `t_historical_figure` VALUES (44, '李时珍', '明代医药学家、博物学家，被后世尊为\"药圣\"', '1518年7月3日', '1593年', '明朝', '湖广蕲州（今湖北省蕲春县）', 'https://history-study.oss-cn-beijing.aliyuncs.com/event&people/625191f16ee948f99e48c68b3cfa7fd9.webp', '李时珍，字东璧，号濒湖山人，明代最伟大的医药学家之一。他出身于一个医学世家，祖父李晓山是一位走方郎中，父亲李言闻是当地名医，曾任太医院吏目。李时珍自幼聪颖过人，但少年时期却屡试不第，这反而使他得以专心于医学研究，最终成就了中国古代药物学的巅峰之作。\n\n李时珍十四岁时随父学医，展现出非凡的医学天赋。他不仅能熟读《内经》《伤寒论》等经典医籍，更善于在实践中发现问题。二十岁左右，李时珍开始独立行医，足迹遍及蕲州及周边地区。在行医过程中，他发现古代本草书籍存在大量错误：药物分类混乱，同名异物、同物异名现象严重，甚至有许多毒性药物被误认为无毒。这些发现促使他萌生了重新编纂一部权威本草著作的念头。\n\n嘉靖三十一年（1552年），三十四岁的李时珍正式开始《本草纲目》的编纂工作。这是一场历时二十七年的浩大工程。李时珍\"搜罗百氏，访采四方\"，先后到武当山、庐山、茅山、牛首山以及湖广、直隶、河南、河北等地考察药物，采集标本。他亲自品尝各种药物，验证其性味功效；向农夫、渔人、樵夫、药农请教，收集民间用药经验；查阅历代医书、经史百家著作八百余种，做了大量读书笔记。在编纂过程中，他创立了先进的药物分类体系，将药物按自然属性分为十六部、六十类，这种分类方法比西方林奈的植物分类法早近两百年。\n\n万历六年（1578年），《本草纲目》终于完稿，全书五十二卷，收录药物一千八百九十二种，附方一万一千零九十六首，附图一千一百六十幅，字数达一百九十余万。这是中国古代内容最丰富、分类最科学的药物学巨著。然而李时珍生前未能亲眼见到此书刊行。他去世后三年，即万历二十四年（1596年），该书才在金陵首次刻印，随即风靡全国，并很快传入日本、朝鲜及东南亚各国，十七世纪后又被译成拉丁文、法文、德文、英文等多种文字，成为全人类共同的医学财富。\n\n除《本草纲目》外，李时珍还著有《濒湖脉学》《奇经八脉考》等医学著作。《濒湖脉学》将脉象归纳为二十七种，以歌诀形式写成，便于初学者记忆，至今仍是中医脉学的重要入门书。《奇经八脉考》则系统研究了奇经八脉的循行路线和主治病症，对针灸学发展有重要贡献。李时珍的医学思想强调实事求是、注重实践，反对迷信古人和空谈玄理，这种科学精神在当时的社会环境下尤为可贵。\n\n李时珍的历史影响极为深远。《本草纲目》不仅是一部药物学著作，更是一部博物学百科全书，涉及植物学、动物学、矿物学、化学等多个学科。达尔文在《物种起源》等著作中多次引用《本草纲目》中的材料，称之为\"中国古代的百科全书\"。1953年，李时珍的肖像被镶嵌在莫斯科大学新落成的世界科学文化名人浮雕上，与牛顿、居里夫人等并列，成为中华民族对世界文明的杰出贡献者。', '本草纲目,濒湖脉学,奇经八脉考,五脏图论,三焦客难', '2026-04-09 16:26:21', '2026-04-09 16:26:21');
INSERT INTO `t_historical_figure` VALUES (45, '郭守敬', '元代天文学家、数学家、水利专家、仪器制造家', '1231年', '1316年', '元朝', '顺德邢台（今河北省邢台市）', 'https://history-study.oss-cn-beijing.aliyuncs.com/event&people/db6e47e5ca3c469baafb2f23ccfad63d.webp', '郭守敬，字若思，元代杰出的科学家，在天文、历法、水利、数学等领域均有卓越贡献，被誉为中国古代科技史上承前启后的集大成者。他出身书香门第，祖父郭荣精通天文、算学，对郭守敬的科学启蒙影响深远。少年时期，郭守敬便展现出非凡的数学天赋，曾根据拓本研究出一幅古代计时器\"莲花漏\"的图样，令时人惊叹不已。\n\n忽必烈即位后，广招天下贤才，郭守敬经好友张文谦推荐入朝，得到重用。中统三年（1262年），他面陈水利六事，提出治理华北水系的系统方案，被任命为提举诸路河渠。此后十余年间，他主持修复了宁夏一带因战乱废弃的古灌渠，灌溉农田九万余顷，使当地农业迅速恢复；又主持开凿通惠河，连接大都与通州，解决了元大都的漕运难题，至今北京积水潭仍保留着郭守敬纪念馆以纪念这一功绩。\n\n至元十三年（1276年），元世祖忽必烈诏令修订新历，郭守敬与王恂、许衡等人奉命编制《授时历》。为精确观测天象，他创制了简仪、高表、仰仪、景符等十余种精密天文仪器，其设计之精巧、工艺之精湛，在当时世界范围内首屈一指。其中简仪是对传统浑仪的重大革新，取消了多余环圈，将赤道装置与地平装置分离，大大提高了观测精度，比丹麦天文学家第谷的同类发明早三百余年。郭守敬还主持了大规模天文测量，在全国设立二十七个观测站，最北延伸至北海（今西伯利亚北部），南至南海（今越南中部），测得冬至时刻精确到近代历法水平，并首次以数学方法推算出回归年长度为365.2425日，与现行公历完全一致，但比格里高利历的颁行早三百年。\n\n《授时历》于至元十八年（1281年）正式颁行，取\"敬授人时\"之意，是中国古代最精密的历法之一，通行三百六十四年，为历代历法之冠。郭守敬晚年仍致力于学术研究，曾试图编制《历议》阐明历法原理，可惜未能完成。他历任太史令、昭文馆大学士、知太史院事等职，封魏国公，享年八十六岁。其科学成就不仅在中国科技史上占有崇高地位，亦对世界天文学发展产生深远影响，国际天文学会以他的名字命名月球上的一座环形山，小行星2012也被命名为\"郭守敬星\"。', '授时历,推步,立成,历议拟稿,仪象法式占,二至晷景考,五星细行考五十多卷,新测二十八舍杂坐诸星入宿去极,新测无名诸星,月离考', '2026-04-09 16:27:03', '2026-04-09 16:27:03');
INSERT INTO `t_historical_figure` VALUES (50, '徐光启', '明末科学家、政治家、农学家、翻译家', '1562年4月24日', '1633年11月8日', '明朝', '南直隶松江府上海县（今上海市徐汇区）', 'https://history-study.oss-cn-beijing.aliyuncs.com/event&people/c708e22188dd427b88769c57f2698924.webp', '徐光启，字子先，号玄扈，晚号玄扈老人，明末杰出的科学家、政治家，中国早期天主教传教士之一，被誉为\"中国近代科学先驱\"。他出生于上海一个商人家庭，自幼聪颖好学，万历二十五年（1597年）中举，万历三十二年（1604年）中进士，选翰林院庶吉士，后历任翰林院检讨、詹事府少詹事、礼部侍郎、礼部尚书兼文渊阁大学士等职，成为明末重要的朝廷重臣。\n\n徐光启一生致力于科学研究和农学实践，其学术成就涵盖天文历法、数学、农学、水利、军事等多个领域。他最为人称道的贡献是与意大利传教士利玛窦合作翻译欧几里得《几何原本》前六卷，这是西方数学著作首次被系统译介到中国，极大地推动了中国数学的发展。\"几何\"一词即由徐光启首创并沿用至今。此外，他还翻译了《测量法义》《勾股义》等西方科学著作，积极引进西方天文仪器和观测方法。\n\n在农学方面，徐光启耗费数十年心血编纂《农政全书》，这是中国历史上最重要的农学著作之一。全书共六十卷，约七十万字，内容涵盖农本、田制、农事、水利、农器、树艺、蚕桑、种植、牧养等多个门类，系统总结了明代及以前的农业生产经验，并融入了他在天津、上海等地亲自试验的农业技术。《农政全书》与《齐民要术》《天工开物》并称中国古代三大农书，对后世农业发展影响深远。\n\n崇祯年间，徐光启主持修订历法，采用西方天文学方法编制《崇祯历书》。虽然该历书因明朝灭亡未能正式颁行，但其科学方法为清代《时宪历》的制定奠定了基础。在军事方面，他积极主张引进西方火器技术，参与红夷大炮的仿制和使用，并撰写《火攻要略》等军事著作。他还多次上疏朝廷，提出练兵、屯田、水利等强国之策，展现出卓越的政治远见。\n\n徐光启于崇祯六年（1633年）病逝于北京，享年七十一岁，谥号文定。他去世后葬于上海法华泾，其墓地现为徐光启墓园，被列为全国重点文物保护单位。作为中西文化交流的先驱，徐光启以开放包容的学术态度，架起了沟通东西方科学的桥梁，其科学精神和爱国情怀至今仍为后人敬仰。', '农政全书,几何原本（译）,崇祯历书,测量法义,勾股义,泰西水法,火攻要略', '2026-04-15 14:17:10', '2026-04-15 14:17:10');
INSERT INTO `t_historical_figure` VALUES (51, '宋应星', '明末科学家、博物学家，《天工开物》作者', '1587年', '约1666年', '明朝', '江西奉新（今江西省宜春市奉新县）', 'https://history-study.oss-cn-beijing.aliyuncs.com/event&people/33c137b0d29b4739a0dda10137bf72d1.webp', '宋应星，字长庚，江西奉新人，明代杰出的科学家、博物学家，被誉为\"中国的狄德罗\"。他出身于书香门第，自幼聪颖好学，博览群书，对经史子集、天文历法、农工技艺皆有涉猎。万历四十三年（1615年），宋应星与兄宋应昇同中举人，时称\"奉新二宋\"。此后他曾六次赴京参加会试，皆未中第，遂绝意科举，转而致力于实学研究。\n\n宋应星生活的时代，正值晚明社会变革之际，商品经济繁荣，手工业技术突飞猛进。他深感士大夫\"重经义轻技艺\"之弊，决心系统总结中国古代农业和手工业生产技术。从崇祯七年（1634年）起，他历任江西分宜县教谕、福建汀州府推官、亳州知府等职，在任期间深入民间，实地考察各类生产工艺，积累了大量第一手资料。崇祯十年（1637年），其代表作《天工开物》三卷十八篇终于付梓，这是中国历史上第一部关于农业和手工业生产的综合性著作。\n\n《天工开物》书名取自《尚书·皋陶谟》\"天工人其代之\"及《易经·系辞》\"开物成务\"，意为顺应自然规律，开发万物之功用。全书分为上中下三编，上编论谷物种植、蚕桑纺织，中编述制盐、制糖、陶瓷、冶炼、舟车、锻造等工艺，下编载五金开采、兵器制造、酿酒、珠玉加工等技术。书中附有123幅精美插图，详细记录了各种生产工具的结构和操作流程，图文并茂，堪称中国古代科技的百科全书。宋应星在书中提出了\"巧夺天工\"的技术哲学，强调人类应效法自然、利用自然，而非掠夺自然，这一思想在当时具有超前性。\n\n除《天工开物》外，宋应星还著有《野议》《论气》《谈天》《思怜诗》等作品。《野议》是一部政论集，针对晚明社会积弊提出改革主张，涉及吏治、军事、财政、教育等诸多方面，体现了他经世致用的实学思想。《论气》和《谈天》则是自然科学著作，探讨声、光、热、磁等物理现象以及天文历法问题，其中关于声音共振、空气湿度的论述颇具科学价值。这些著作与《天工开物》共同构成了宋应星完整的学术体系。\n\n明亡后，宋应星拒绝仕清，隐居乡间，晚年生活困顿，约在康熙五年（1666年）前后去世，享年约八十岁。他的科学成就长期被埋没，直到清末民初才重新受到重视。《天工开物》在清代一度失传，却流传至日本、欧洲，被翻译成多种文字，对世界科技发展产生深远影响。日本学者薮内清称其为\"中国17世纪的工艺百科全书\"，英国科学史家李约瑟更是高度评价宋应星，将其与英国哲学家培根相提并论，认为他是\"中国的阿格里科拉\"。\n\n宋应星的历史贡献在于开创了中国实学研究的新传统。他打破\"重道轻器\"的儒学藩篱，将技艺生产提升至学术研究的高度，建立了系统的技术知识体系。其著作不仅保存了大量珍贵的古代工艺资料，更体现了科学实验与理论总结相结合的研究方法，对后世乾嘉学派的考据实学、晚清洋务运动的\"中体西用\"论皆有启发。今日中国奉新县建有宋应星纪念馆，其故里也被列为文物保护单位，以纪念这位伟大的古代科学家。', '天工开物,野议,论气,谈天,思怜诗', '2026-04-15 14:18:36', '2026-04-15 14:18:36');
INSERT INTO `t_historical_figure` VALUES (52, '祖冲之', '南朝宋齐时期数学家、天文学家、机械发明家', '429年', '500年', '南朝宋、齐', '范阳郡遒县（今河北省涞水县）', 'https://history-study.oss-cn-beijing.aliyuncs.com/event&people/8dd0f43beab447dc97f1578f7d941fb5.webp', '祖冲之，字文远，范阳遒县人，生于南朝宋文帝元嘉六年（429年），卒于南朝齐东昏侯永元二年（500年），是中国古代杰出的数学家、天文学家和机械发明家。祖冲之出身官宦世家，其祖父祖昌曾任刘宋大匠卿，掌管土木工程，父亲祖朔之也任奉朝请。这样的家庭背景使祖冲之自幼得以接触天文历算之学，为其日后的学术成就奠定了基础。\n\n祖冲之年轻时即进入华林学省学习，这是南朝政府设立的专门学术机构，汇聚了当时最优秀的学者。他在这里潜心研究天文、数学，逐渐展现出非凡的才华。宋孝武帝时期，祖冲之被安排至总明观任职，这是全国最高的科研学术机构，相当于现代的国家科学院。在这里，他得以阅读大量国家藏书，接触到前代学者的研究成果，学术视野大为开阔。\n\n祖冲之最杰出的贡献在于数学领域。他在刘徽割圆术的基础上，将圆周率π精确到小数点后第七位，即3.1415926与3.1415927之间，并提出约率22/7和密率355/113。这一成果在当时世界范围内遥遥领先，直到十五世纪阿拉伯数学家阿尔·卡西和十六世纪法国数学家韦达才分别打破这一纪录。密率355/113的精确程度极高，分母和分子都保持在三位数以内，在数学史上具有重要地位，日本数学史家三上义夫甚至建议将这一数值命名为\"祖率\"以纪念其贡献。\n\n在天文学方面，祖冲之编制了《大明历》，这是当时最先进的历法。他首次将岁差引入历法计算，测定回归年长度为365.24281481日，与现代测量值365.24219878日仅差约46秒。他还精确测定了交点月长度为27.21223日，与现代值27.21222日几乎完全一致。《大明历》中采用的391年置144闰的新闰周，比古历更为精密。尽管这一历法因遭到宠臣戴法兴的反对而未能及时施行，直到祖冲之去世十年后的510年才由他的儿子祖暅正式颁行，但其科学价值得到了后世公认。\n\n祖冲之还是一位杰出的机械发明家。他重造了指南车，采用铜制机件和齿轮传动装置，使指南车真正实现了定向功能，而非依赖磁石。他还制造了水碓磨、千里船等机械装置。据记载，千里船\"日行百余里\"，可能是利用水力或人力推进的船只。此外，他还设计了漏壶等计时仪器，并著有《漏经》一卷。在兵器制造方面，他制造了\"欹器\"等装置，展现了全面的工程技术才能。\n\n祖冲之的著作极为丰富，包括《缀术》五卷、《九章术义注》九卷、《重差注》一卷等数学著作，以及《大明历》、《漏经》等天文历法著作。可惜的是，除《大明历》的部分内容通过《宋书·历志》流传下来外，其余数学著作大多散佚。《缀术》在唐代被列为国子监算学教材，学习年限长达四年，是十部算经中学习时间最长的，可见其内容深奥。日本、朝鲜也曾采用《缀术》作为教材，影响深远。\n\n祖冲之的儿子祖暅也是一位杰出的数学家，父子共同解决了球体积的计算问题，提出了\"幂势既同，则积不容异\"的原理，即著名的\"祖暅原理\"，在西方被称为卡瓦列利原理，但比意大利数学家卡瓦列利早一千多年。祖冲之家族几代人都致力于科学研究，形成了独特的学术传统，在中国科学史上极为罕见。\n\n祖冲之的科学成就不仅在当时处于世界领先地位，而且对后世产生了深远影响。他的圆周率计算成果被载入《隋书·律历志》，成为后世研究的重要基础。唐代数学家李淳风等人在注释《九章算术》时，多次引用祖冲之的论述。宋代科学家沈括在《梦溪笔谈》中也对祖冲之推崇备至。在国际学术界，祖冲之的名字与圆周率紧密相连，月球背面的一座环形山被命名为\"祖冲之环形山\"，以纪念这位伟大的中国科学家。', '缀术,大明历,九章术义注,重差注,漏经', '2026-04-15 14:20:19', '2026-04-15 14:20:19');
INSERT INTO `t_historical_figure` VALUES (53, '郑和', '明代航海家、外交家、军事家', '1371年', '1433年', '明朝', '云南昆阳（今云南省晋宁县）', NULL, '郑和，本姓马，小名三宝，又作三保，回族，云南昆阳人，明代杰出的航海家、外交家和军事家。郑和出生于明洪武四年（1371年），其家族世代信奉伊斯兰教，祖父和父亲都曾前往麦加朝圣，被尊称为\"哈只\"。幼年时，郑和家境殷实，生活优渥，然而洪武十四年（1381年），明军平定云南，郑和的父亲在战乱中身亡，年仅十岁的郑和被明军俘虏，惨遭阉割，随后被送入燕王府为宦官。\n\n在燕王府中，郑和因其聪明机敏、勤奋好学而深受燕王朱棣赏识。建文元年（1399年），朱棣发动\"靖难之役\"，郑和随侍左右，屡立战功。永乐二年（1404年），朱棣为表彰其功绩，赐姓郑，并升任内官监太监，时称\"三宝太监\"。此时的郑和已成长为一位具有卓越军事才能和丰富地理知识的宦官，为其日后的大规模航海活动奠定了坚实基础。\n\n永乐三年（1405年），明成祖朱棣为宣扬国威、加强与海外各国的联系、寻找失踪的建文帝，任命郑和为正使太监，率领庞大的船队首次下西洋。这支船队规模空前，拥有宝船六十二艘，官兵、水手、工匠等共计二万七千余人，是当时世界上最庞大的海上力量。郑和船队从刘家港出发，经占城、爪哇、苏门答腊、锡兰等地，最终抵达印度西海岸的古里国，历时两年多才返回。此次航行不仅建立了明朝与东南亚、南亚诸国的朝贡贸易关系，更展示了明朝强大的海上实力。\n\n此后二十余年间，郑和又先后六次率领船队下西洋，其航线不断延伸，最远到达东非海岸的木骨都束（今索马里摩加迪沙）、卜喇哇（今索马里布拉瓦）和麻林（今肯尼亚马林迪）等地。郑和七下西洋，历时二十八年，访问了三十多个国家和地区，开辟了西太平洋至印度洋的远洋航线，绘制了详细的航海图，建立了完整的航海档案。其船队采用先进的航海技术，如罗盘定向、牵星过洋、海图导航等，在当时世界航海史上处于领先地位。\n\n郑和的航海活动具有深远的政治、经济和文化意义。政治上，他成功调解了东南亚各国之间的矛盾冲突，维护了区域和平稳定，确立了明朝在朝贡体系中的核心地位；经济上，促进了中外贸易往来，中国的丝绸、瓷器、茶叶远销海外，同时引进了香料、宝石、珍稀动物等异域物产；文化上，推动了中华文明与伊斯兰文明、印度文明、非洲文明的交流互鉴，郑和本人还曾在锡兰山、古里等地建立碑刻，记录航海事迹，传播中华文化。值得一提的是，郑和船队始终秉持和平外交理念，从未以武力掠夺殖民地，这与西方殖民者的航海活动形成鲜明对比。\n\n宣德八年（1433年），郑和在第七次下西洋途中病逝于古里国，享年六十二岁。其遗体被船员运回，葬于南京牛首山。郑和去世后，明朝因财政困难、北方边患加剧等原因，逐渐停止了大规模航海活动，其航海档案也多被销毁或遗失。然而，郑和开创的伟大航海事业永载史册，他被誉为\"大航海时代的先驱\"，其航海壮举比哥伦布发现新大陆早八十七年，比达·伽马开辟印度航线早九十三年。近代以来，随着《郑和航海图》等文献的重新发现和研究，郑和的历史地位得到国际社会广泛认可，成为中华民族勇于探索、开放包容精神的象征。', '郑和航海图,娄东刘家港天妃宫石刻通番事迹记,天妃灵应之记碑', '2026-04-15 14:22:51', '2026-04-15 14:22:51');
INSERT INTO `t_historical_figure` VALUES (54, '司马迁', '西汉史学家、文学家、思想家', '前145年', '约前86年', '西汉', '左冯翊夏阳（今陕西省韩城市）', NULL, '司马迁，字子长，西汉伟大的史学家、文学家、思想家，被后世尊称为\"史圣\"。他出身于史官世家，其父司马谈为汉武帝时期的太史令，掌管天文历法与典籍文献。司马迁自幼聪慧好学，十岁便能诵读古文，后师从经学大师孔安国、董仲舒，深受儒家思想熏陶，同时也广泛涉猎诸子百家之学，为其日后撰写巨著奠定了深厚的学术根基。\n\n二十岁那年，司马迁开始游历天下，足迹遍及江淮流域、齐鲁大地、梁楚故都。他考察山川地理，探访历史遗迹，搜集民间传说，访问耆老故旧，这种实地考察的治学方法使他获得了远超书斋学者的鲜活史料。例如，他亲赴会稽探访禹穴，至汨罗江凭吊屈原，上九嶷山瞻仰舜帝陵寝，这些经历都深刻影响了《史记》的叙事风格与历史视野。游历归来后，司马迁入仕为郎中，多次随汉武帝巡行封禅，并奉命出使西南夷，积累了丰富的政治阅历。\n\n汉武帝元封元年（前110年），司马谈临终前将修史遗志托付于司马迁。三年后，司马迁继任太史令，得以饱览朝廷金匮石室之藏，着手撰写《史记》。然而天汉二年（前99年），李陵出击匈奴兵败投降，司马迁因替李陵辩护而触怒武帝，被处以腐刑。这一奇耻大辱几乎摧毁了他的精神，但为了实现父亲的遗志、完成\"究天人之际，通古今之变，成一家之言\"的学术理想，他忍辱负重，发愤著书，终于在征和二年（前91年）完成了这部旷世巨著。\n\n《史记》全书一百三十篇，五十二万余字，记载了上起黄帝、下至汉武帝太初年间约三千年的历史，是中国第一部纪传体通史。其体例分为本纪、表、书、世家、列传五部分，开创了后世正史的编纂范式。司马迁秉笔直书，不虚美、不隐恶，既歌颂陈涉起义的历史功绩，也为刺客游侠立传，更对汉武帝的穷兵黩武、封禅求仙多有批评。这种独立的批判精神，使《史记》成为中国史学史上最具思想深度的著作。\n\n司马迁的文学成就同样卓越。《史记》的叙事艺术达到了中国古文的巅峰，其人物刻画栩栩如生，语言生动传神，情节跌宕起伏。\"鸿门宴\"\"项羽本纪\"\"刺客列传\"等篇章，既是严谨的历史记录，又是精彩的文学作品，被鲁迅誉为\"史家之绝唱，无韵之离骚\"。司马迁还首创了\"太史公曰\"的论赞形式，以简洁精辟的史论表达历史见解，影响深远。\n\n司马迁晚年的事迹记载甚少，大约卒于汉武帝末年或汉昭帝初年。他的著作最初以抄本形式流传，至东汉时已广为人知。唐代以后，《史记》被列为\"二十四史\"之首，其史学方法与文学技巧成为后世典范。司马迁所确立的\"实录\"精神、通史视野、民本思想，以及面对逆境不屈不挠的人格力量，成为中华民族宝贵的精神遗产。', '史记,报任安书,悲士不遇赋', '2026-04-15 14:25:16', '2026-04-15 14:25:16');

-- ----------------------------
-- Table structure for t_quiz
-- ----------------------------
DROP TABLE IF EXISTS `t_quiz`;
CREATE TABLE `t_quiz`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键',
  `question` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '题目内容',
  `quiz_type` tinyint NOT NULL DEFAULT 1 COMMENT '题目类型：1=单选，2=多选',
  `option_a` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '选项A',
  `option_b` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '选项B',
  `option_c` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '选项C',
  `option_d` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '选项D',
  `correct_options` varchar(10) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '正确答案：单选存A/B/C/D，多选存A,B,C形式',
  `explanation` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '答案解析',
  `difficulty` tinyint NOT NULL DEFAULT 1 COMMENT '难度：1=简单，2=中等，3=困难',
  `tags` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '知识点标签',
  `status` tinyint NOT NULL DEFAULT 1 COMMENT '状态：0=下线，1=正常',
  `source` tinyint NOT NULL DEFAULT 1 COMMENT '来源：1=人工录入，2=大模型生成',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 101 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '问答题目表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of t_quiz
-- ----------------------------
INSERT INTO `t_quiz` VALUES (1, '中国历史上唯一一位正统女皇帝武则天，其建立的朝代国号是？', 1, '大唐', '大周', '大齐', '大汉', 'B', '武则天（624年－705年），本名珝，后改名曌。天授元年（690年），武则天宣布改唐为周，自立为帝，定洛阳为神都，建立武周。神龙元年（705年），神龙政变爆发，武则天被迫退位，唐中宗复辟，恢复唐朝。', 1, '唐朝,女皇帝', 1, 1);
INSERT INTO `t_quiz` VALUES (2, '以下哪些是秦始皇的功绩？', 2, '统一六国', '修建长城', '开创科举制度', '统一文字度量衡', 'A,B,D', '秦始皇的主要功绩包括：统一六国，结束战国割据局面；修建长城抵御北方匈奴；统一文字、度量衡、货币，促进国家统一。科举制度始于隋朝，并非秦始皇创立。', 2, '秦朝,秦始皇', 1, 1);
INSERT INTO `t_quiz` VALUES (3, '中国历史上第一个统一的多民族中央集权国家是？', 1, '夏朝', '商朝', '秦朝', '汉朝', 'C', '公元前221年，秦始皇嬴政统一六国，建立秦朝，创立皇帝制度、郡县制等中央集权制度，是中国历史上第一个统一的多民族中央集权国家。', 1, '秦朝,统一,中央集权', 1, 2);
INSERT INTO `t_quiz` VALUES (4, '下列哪些制度是隋朝创立并为后世沿用的？', 2, '三省六部制', '科举制', '郡县制', '行省制', 'AB', '隋朝创立三省六部制和科举制。三省六部制分割相权、加强皇权；科举制打破门阀垄断，成为后世选官主要制度。郡县制始于秦朝，行省制始于元朝。', 2, '隋朝,三省六部制,科举制,制度创新', 1, 2);
INSERT INTO `t_quiz` VALUES (5, '汉武帝为加强中央集权，采取了以下哪些措施？', 2, '颁布\'推恩令\'', '设立刺史制度', '\'罢黜百家，独尊儒术\'', '实行郡国并行制', 'ABC', '汉武帝颁布\'推恩令\'削弱诸侯王势力，设刺史监察地方，采纳董仲舒建议独尊儒术。郡国并行制是汉初刘邦实行的制度，并非汉武帝创立。', 2, '汉武帝,推恩令,刺史,独尊儒术', 1, 2);
INSERT INTO `t_quiz` VALUES (6, '元朝在地方行政制度上的重大创新是？', 1, '郡县制', '行省制', '道州县制', '路府州县制', 'B', '元朝创立行省制度，是中国省制的开端，加强了中央对地方的控制，为明清所继承，影响延续至今。', 1, '元朝,行省制,地方行政', 1, 2);
INSERT INTO `t_quiz` VALUES (7, '明太祖朱元璋为强化皇权，采取了以下哪项措施？', 1, '设立三省六部', '废除丞相制度', '创立军机处', '实行分封制', 'B', '1380年，朱元璋以胡惟庸案为契机，废除丞相制度，权分六部，皇帝直接统领，使君主专制达到新高度。军机处是清朝雍正所设。', 1, '明朝,朱元璋,废丞相,君主专制', 1, 2);
INSERT INTO `t_quiz` VALUES (8, '清朝军机处的设立标志着什么？', 1, '中央官制的完善', '君主专制达到顶峰', '内阁制度的成熟', '地方行政的改革', 'B', '雍正年间设立军机处，军机大臣跪受笔录、上传下达，完全听命于皇帝，标志着中国古代君主专制中央集权制度发展到顶峰。', 1, '清朝,军机处,雍正,君主专制', 1, 2);
INSERT INTO `t_quiz` VALUES (9, '下列关于中国古代选官制度的演变，正确的有？', 2, '汉朝实行察举制', '魏晋南北朝实行九品中正制', '隋朝开始实行科举制', '宋朝废除科举制', 'ABC', '汉朝察举制以品德才能荐举人才；魏晋九品中正制由中正官评定等级；隋朝开创科举制。宋朝是完善科举而非废除，废除科举是1905年清末新政时期。', 2, '选官制度,察举制,九品中正制,科举制', 1, 2);
INSERT INTO `t_quiz` VALUES (10, '西周分封制与秦朝郡县制的本质区别在于？', 1, '官员产生方式不同', '行政区划名称不同', '经济制度不同', '军事制度不同', 'A', '分封制下诸侯世袭统治，有很强独立性；郡县制下官员由中央任免、不得世袭，是官僚政治取代贵族政治的标志，本质区别在于官员产生方式。', 2, '西周,秦朝,分封制,郡县制,官僚政治', 1, 2);
INSERT INTO `t_quiz` VALUES (11, '唐朝三省六部制中，负责决策的机构是？', 1, '尚书省', '门下省', '中书省', '枢密院', 'C', '中书省负责草拟诏令（决策），门下省负责审核封驳，尚书省负责执行。三省分工明确，相互牵制。枢密院是唐宋时期掌军事的机构。', 1, '唐朝,三省六部制,中书省', 1, 2);
INSERT INTO `t_quiz` VALUES (12, '王安石变法中，为限制高利贷盘剥、增加政府收入而推行的措施是？', 1, '青苗法', '募役法', '方田均税法', '保甲法', 'A', '青苗法在青黄不接时由政府贷款给农民，收取较低利息，既限制地主高利贷盘剥，又增加政府财政收入。募役法改差役为雇役，方田均税法清丈土地均摊税负，保甲法为军事组织。', 3, '北宋,王安石变法,青苗法,变法措施', 1, 2);
INSERT INTO `t_quiz` VALUES (13, '战国时期，秦国名将白起在长平之战中击败了哪位赵国将领，导致赵国四十万大军被坑杀？', 1, '廉颇', '李牧', '赵括', '赵奢', 'C', '长平之战（公元前260年）是战国后期决定性的战役。赵孝成王中秦国反间计，用赵括替换坚守不出的廉颇。赵括纸上谈兵，贸然出击，被白起包围，最终赵军投降后四十余万被坑杀，赵国元气大伤。', 1, '战国,长平之战,白起,赵括', 1, 2);
INSERT INTO `t_quiz` VALUES (14, '汉武帝时期，哪位将领多次率军出击匈奴，取得漠北之战大捷，封狼居胥，成为后世武将最高荣誉象征？', 1, '卫青', '霍去病', '李广', '李陵', 'B', '霍去病（公元前140年—前117年）是西汉名将，18岁为剽姚校尉，六次出击匈奴，在漠北之战中大败左贤王部，封狼居胥山、禅于姑衍，登临翰海而还。\"封狼居胥\"成为后世武将最高战功的代名词。', 1, '西汉,汉武帝,匈奴,霍去病,封狼居胥', 1, 2);
INSERT INTO `t_quiz` VALUES (15, '下列关于赤壁之战（208年）的表述，正确的有哪些？', 2, '曹操率二十余万大军南下，号称八十万', '孙刘联军由周瑜、诸葛亮共同指挥', '战役结果为曹操大败，奠定三国鼎立基础', '火攻战术由黄盖献计并亲自执行', 'ACD', '赤壁之战中，曹操兵力二十余万（号称八十万），孙刘联军约五万，由周瑜任总指挥，诸葛亮主要负责联吴外交。黄盖献火攻之计，以诈降方式接近曹军，点燃火船大破曹军。此战阻止曹操统一南方，奠定三国鼎立格局。', 2, '三国,赤壁之战,曹操,周瑜,诸葛亮', 1, 2);
INSERT INTO `t_quiz` VALUES (16, '唐朝安史之乱中，哪位将领指挥了著名的睢阳保卫战，以数千兵力阻挡叛军十余万，最终粮尽食人，城破殉国？', 1, '张巡', '许远', '南霁云', '雷万春', 'A', '张巡（708年—757年）在至德二载（757年）坚守睢阳十月，以六千八百士卒对抗尹子奇十三万叛军，大小四百余战，杀敌十二万。最终粮尽，先食茶纸、树皮，后食人，城破被俘，不屈而死。', 2, '唐朝,安史之乱,睢阳保卫战,张巡', 1, 2);
INSERT INTO `t_quiz` VALUES (17, '南宋时期，岳飞率领岳家军北伐，在哪场战役中取得大捷，收复郑州、洛阳等地，进抵朱仙镇，距开封仅四十五里？', 1, '郾城大捷', '颍昌大捷', '朱仙镇大捷', '偃城大捷', 'A', '郾城大捷（1140年）是岳飞北伐的巅峰之战。岳飞以少胜多，大破金兀术精锐铁浮图和拐子马，随后收复郑州、洛阳，进军朱仙镇。此时宋高宗连下十二道金牌强令班师，十年之功毁于一旦。', 2, '南宋,岳飞,郾城大捷,北伐,靖康之耻', 1, 2);
INSERT INTO `t_quiz` VALUES (18, '明朝永乐年间，郑和七次下西洋，其船队最远到达的地区是哪里？', 1, '印度半岛', '阿拉伯半岛', '东非海岸', '红海沿岸', 'C', '郑和七下西洋（1405年—1433年），船队规模庞大，最多时达两百余艘船、两万七千余人。前三次到达印度半岛，第四至七次经阿拉伯半岛到达东非海岸，最远至木骨都束（今索马里摩加迪沙）和麻林（今肯尼亚马林迪）。', 1, '明朝,郑和下西洋,永乐,航海,外交', 1, 2);
INSERT INTO `t_quiz` VALUES (19, '下列关于鸦片战争（1840—1842年）的表述，正确的有哪些？', 2, '英国发动战争的根本目的是打开中国市场', '林则徐虎门销烟是战争的直接导火索', '清政府被迫签订《南京条约》，割让香港岛', '战争期间三元里人民自发抗击英军', 'ABCD', '鸦片战争是英国为扭转对华贸易逆差、打开中国市场而发动的侵略战争。林则徐1839年虎门销烟成为直接借口。1842年清政府战败，签订《南京条约》，割香港岛、赔款、开放五口通商。1841年广州三元里民众自发组织抗英斗争。', 1, '清朝,鸦片战争,南京条约,林则徐,香港', 1, 2);
INSERT INTO `t_quiz` VALUES (20, '抗日战争时期，八路军在华北发动的百团大战（1940年），其主要作战目标是什么？', 1, '正面战场配合国军作战', '破袭日军交通线，摧毁日伪据点', '保卫延安党中央', '开辟敌后抗日根据地', 'B', '百团大战由彭德怀指挥，1940年8月至12月进行，出动105个团约40万人，主要目标是破袭正太铁路为重点的交通线，摧毁日伪据点，反击日军的\"囚笼政策\"。这是抗战期间八路军发动的规模最大、持续时间最长的战役。', 1, '抗日战争,百团大战,八路军,彭德怀', 1, 2);
INSERT INTO `t_quiz` VALUES (21, '1950年抗美援朝战争中，中国人民志愿军跨过鸭绿江后取得的第一场大胜是哪场战役？', 1, '上甘岭战役', '长津湖战役', '第一次战役（温井、两水洞之战）', '金城战役', 'C', '1950年10月25日，志愿军第40军118师在两水洞、丰下洞地区与韩军遭遇，打响入朝第一仗，取得温井、两水洞战斗胜利。随后第一次战役至11月5日结束，歼敌1.5万，将敌军从鸭绿江边赶到清川江以南，稳定了战局。', 2, '抗美援朝,志愿军,第一次战役,彭德怀', 1, 2);
INSERT INTO `t_quiz` VALUES (22, '下列关于中国古代著名外交事件的表述，正确的有哪些？', 2, '张骞出使西域，开辟了丝绸之路', '玄奘西行天竺取经，著有《大唐西域记》', '鉴真六次东渡，最终成功抵达日本传播佛教', '郑成功收复台湾，是从荷兰殖民者手中收回', 'ABCD', '张骞两次出使西域（前138年、前119年），开辟丝绸之路；玄奘贞观年间西行求法17年，归国后著《大唐西域记》；鉴真天宝年间六次东渡，754年成功抵日，建唐招提寺；郑成功1661年率军东征，1662年迫使荷兰投降，收复台湾。', 3, '外交,张骞,玄奘,鉴真,郑成功,丝绸之路', 1, 2);
INSERT INTO `t_quiz` VALUES (23, '下列哪项发明被誉为中国古代四大发明之一，并对世界航海事业产生了重大影响？', 1, '造纸术', '印刷术', '指南针', '火药', 'C', '指南针是中国古代四大发明之一，北宋时期开始应用于航海，大大促进了世界航海事业的发展，为地理大发现提供了重要条件。', 1, '四大发明,科技,航海', 1, 2);
INSERT INTO `t_quiz` VALUES (24, '被誉为\'书圣\'的东晋书法家王羲之的代表作是？', 1, '《兰亭集序》', '《祭侄文稿》', '《寒食帖》', '《九成宫醴泉铭》', 'A', '《兰亭集序》是王羲之的代表作，被誉为\'天下第一行书\'，创作于永和九年（353年）兰亭雅集之时。', 1, '书法,王羲之,东晋', 1, 2);
INSERT INTO `t_quiz` VALUES (25, '下列哪些属于唐代诗人李白的名句？', 2, '飞流直下三千尺，疑是银河落九天', '会当凌绝顶，一览众山小', '长风破浪会有时，直挂云帆济沧海', '天生我材必有用，千金散尽还复来', 'ACD', 'A出自《望庐山瀑布》，C出自《行路难》，D出自《将进酒》，均为李白名句。B出自杜甫《望岳》。', 2, '唐诗,李白,诗歌名句', 1, 2);
INSERT INTO `t_quiz` VALUES (26, '北宋沈括所著的《梦溪笔谈》主要涉及哪些领域的内容？', 2, '天文历法', '数学计算', '医药学', '文学艺术', 'ABC', '《梦溪笔谈》是一部综合性笔记体著作，内容涵盖天文、数学、物理、化学、生物、地质、地理、气象、医药、农学、工程技术、文学、史事、音乐和美术等，被英国科学史家李约瑟誉为\'中国科学史上的里程碑\'。', 2, '科技,沈括,宋代', 1, 2);
INSERT INTO `t_quiz` VALUES (27, '元代杂剧作家关汉卿的代表作《窦娥冤》属于哪种戏剧题材？', 1, '历史剧', '公案剧', '爱情剧', '神话剧', 'B', '《窦娥冤》是关汉卿最著名的杂剧作品，讲述了窦娥被冤枉处死、最终昭雪的故事，属于公案剧（即断案剧）题材，深刻揭露了元代社会的黑暗。', 1, '元曲,关汉卿,戏剧', 1, 2);
INSERT INTO `t_quiz` VALUES (28, '明代医药学家李时珍历时27年编撰的药物学巨著是？', 1, '《黄帝内经》', '《伤寒杂病论》', '《本草纲目》', '《千金方》', 'C', '《本草纲目》是李时珍编撰的药物学巨著，收录药物1892种，附方11096首，被誉为\'东方药学巨典\'，对后世医药学发展影响深远。', 1, '医药,李时珍,明代', 1, 2);
INSERT INTO `t_quiz` VALUES (29, '关于中国古代绘画艺术，下列说法正确的有？', 2, '顾恺之提出\'以形写神\'的绘画理论', '张择端的《清明上河图》描绘了北宋汴京的繁华景象', '\'元四家\'指黄公望、王蒙、倪瓒、吴镇', '清代\'扬州八怪\'以郑燮（郑板桥）为代表', 'ABCD', '顾恺之是东晋画家，提出\'以形写神\'；《清明上河图》是北宋张择端的风俗画杰作；\'元四家\'是元代山水画的代表；\'扬州八怪\'是清代中期活跃于扬州的一批画家，郑板桥以画竹著称。', 3, '绘画,艺术史,历代画家', 1, 2);
INSERT INTO `t_quiz` VALUES (30, '被誉为\'中国17世纪的工艺百科全书\'的著作是？', 1, '《天工开物》', '《农政全书》', '《齐民要术》', '《梦溪笔谈》', 'A', '《天工开物》由明代宋应星编撰，系统记载了农业和手工业生产技术，涵盖机械、砖瓦、陶瓷、硫磺、烛、纸、兵器、火药、纺织、染色、制盐、采煤、榨油等，被外国学者誉为\'中国17世纪的工艺百科全书\'。', 2, '科技,明代,手工业', 1, 2);
INSERT INTO `t_quiz` VALUES (31, '下列哪些作品属于中国古典四大名著？', 2, '《三国演义》', '《水浒传》', '《西游记》', '《金瓶梅》', 'ABC', '中国古典四大名著是《三国演义》（罗贯中）、《水浒传》（施耐庵）、《西游记》（吴承恩）、《红楼梦》（曹雪芹）。《金瓶梅》虽为明代长篇世情小说，但不属于四大名著。', 1, '小说,四大名著,文学', 1, 2);
INSERT INTO `t_quiz` VALUES (32, '清代京剧形成过程中，下列哪些因素起到了重要作用？', 2, '徽班进京', '汉调艺人参与', '昆曲艺术的融入', '梆子腔的影响', 'ABCD', '京剧形成于清代乾隆五十五年（1790年）徽班进京后，在徽调、汉调基础上，吸收昆曲、秦腔（梆子腔）等剧种的优点，经过长期融合演变而成，是中国最具影响力的戏曲剧种。', 3, '戏曲,京剧,清代', 1, 2);
INSERT INTO `t_quiz` VALUES (33, '战国时期，秦国商鞅变法中\"废井田，开阡陌\"措施的主要作用是', 1, '确立土地国有制度', '承认土地私有，允许买卖', '推行均田制', '实行屯田制', 'B', '商鞅变法废除井田制，开阡陌封疆，承认土地私有并允许自由买卖，确立了封建土地私有制，促进了秦国农业发展。', 1, '商鞅变法,土地制度,战国时期', 1, 2);
INSERT INTO `t_quiz` VALUES (34, '西汉时期，汉武帝为增加财政收入、抑制富商大贾而采取的经济措施包括', 2, '实行盐铁官营', '推行均输平准', '征收算缗告缗', '开放山林川泽', 'ABC', '汉武帝时期，桑弘羊等人推行盐铁官营、均输平准政策，并征收算缗钱、鼓励告缗，打击富商，增加国库收入。开放山林川泽与史实相反。', 2, '汉武帝,经济政策,盐铁官营', 1, 2);
INSERT INTO `t_quiz` VALUES (35, '唐朝中期，杨炎推行的\"两税法\"与之前的租庸调制相比，主要变化是', 1, '以人丁为主要征税标准', '以资产和田亩为主要征税标准', '征收实物为主', '仅征收货币', 'B', '两税法改变了租庸调制以人丁为主的征税原则，改为以资产和田亩为标准，分夏秋两季征收，适应了土地兼并后的社会变化。', 1, '两税法,唐朝,赋税制度', 1, 2);
INSERT INTO `t_quiz` VALUES (36, '北宋时期，四川地区出现的世界上最早的纸币是', 1, '交子', '会子', '关子', '钱引', 'A', '北宋前期，四川地区因铁钱流通不便，民间出现\"交子\"，后由政府官办，是世界上最早的纸币。会子、关子为南宋纸币。', 1, '交子,纸币,北宋经济', 1, 2);
INSERT INTO `t_quiz` VALUES (37, '明朝张居正改革中，推行\"一条鞭法\"的核心内容是', 1, '将赋役合并，计亩征银', '恢复租庸调制', '实行两税法', '推行摊丁入亩', 'A', '一条鞭法将原来的田赋、徭役及杂税合并为一，按亩折算缴纳银两，简化了税制，促进了商品经济发展。', 1, '一条鞭法,张居正,明朝经济', 1, 2);
INSERT INTO `t_quiz` VALUES (38, '清朝雍正时期推行的\"摊丁入亩\"政策，其历史意义包括', 2, '废除人头税，减轻无地农民负担', '放松了对农民的人身控制', '彻底解决了土地兼并问题', '标志着中国古代赋税制度的成熟', 'ABD', '摊丁入亩将丁银摊入田赋征收，废除了人头税，减轻了无地少地农民负担，放松了人身控制，是中国古代赋税制度成熟的标志，但并未解决土地兼并问题。', 2, '摊丁入亩,清朝,赋税制度', 1, 2);
INSERT INTO `t_quiz` VALUES (39, '中国古代\"重农抑商\"政策长期存在的主要原因包括', 2, '保障国家赋税和徭役来源', '维护小农经济稳定以巩固统治', '商人流动性强不利于社会控制', '商业利润低于农业收入', 'ABC', '重农抑商政策旨在保障农业劳动力、稳定赋役来源、维护社会秩序，并非因为商业利润低。实际上商业利润往往高于农业。', 2, '重农抑商,经济政策,古代中国', 1, 2);
INSERT INTO `t_quiz` VALUES (40, '隋唐时期实行的\"租庸调制\"中，\"庸\"指的是', 1, '田租', '户调', '以绢布代役', '徭役本身', 'C', '租庸调制中，租为田租，调为户调，庸指纳绢或布代役。这一制度保证了农民生产时间，促进了农业发展。', 1, '租庸调制,隋唐,赋税制度', 1, 2);
INSERT INTO `t_quiz` VALUES (41, '下列关于中国古代经济重心南移的表述，正确的是', 2, '魏晋南北朝时期开始南移', '安史之乱后加速南移', '南宋时期最终完成', '南移主要原因是北方战乱', 'ABCD', '经济重心南移始于魏晋南北朝，唐安史之乱后北方破坏严重，南方加速发展，至南宋时南方人口、农业、手工业全面超越北方，最终完成。', 3, '经济重心南移,古代经济,区域发展', 1, 2);
INSERT INTO `t_quiz` VALUES (42, '明朝中后期，江南地区出现\"机户出资，机工出力\"现象，其本质是', 1, '官营手工业的发展', '资本主义萌芽的产生', '小农经济的强化', '租佃关系的普遍化', 'B', '机户拥有生产资料，机工靠出卖劳动力为生，二者形成雇佣关系，这是资本主义生产关系的萌芽，主要出现在江南丝织业等行业。', 3, '资本主义萌芽,明朝,雇佣关系', 1, 2);
INSERT INTO `t_quiz` VALUES (43, '中国历史上第一个统一的多民族中央集权国家是？', 1, '夏朝', '商朝', '秦朝', '汉朝', 'C', '公元前221年，秦始皇嬴政灭六国，建立秦朝，是中国历史上第一个统一的多民族中央集权国家，确立了皇帝制度、郡县制等影响深远的制度。', 1, '秦朝,秦始皇,统一六国', 1, 2);
INSERT INTO `t_quiz` VALUES (44, '下列哪些事件发生在唐朝？', 2, '贞观之治', '开元盛世', '安史之乱', '黄巢起义', 'ABCD', '贞观之治是唐太宗时期，开元盛世是唐玄宗前期，安史之乱发生于755年，黄巢起义发生于875年，均为唐朝重大历史事件。', 2, '唐朝,贞观之治,开元盛世,安史之乱', 1, 2);
INSERT INTO `t_quiz` VALUES (45, '\'卧薪尝胆\'典故的主人公是？', 1, '夫差', '勾践', '范蠡', '伍子胥', 'B', '春秋时期，越王勾践被吴王夫差打败后，卧薪尝胆、发愤图强，最终灭吴复国，成为春秋最后一位霸主。', 1, '春秋,勾践,吴越争霸,成语典故', 1, 2);
INSERT INTO `t_quiz` VALUES (46, '下列关于郑和下西洋的说法，正确的是？', 2, '发生在明朝永乐年间', '最远到达非洲东海岸和红海沿岸', '比哥伦布发现新大陆早约半个世纪', '主要目的是开拓海外殖民地', 'ABC', '郑和七下西洋（1405-1433年）是明成祖时期的壮举，最远到达非洲东海岸，比哥伦布1492年航行早约87年。其主要目的是宣扬国威、发展朝贡贸易，而非殖民扩张。', 2, '明朝,郑和,航海,中外交流', 1, 2);
INSERT INTO `t_quiz` VALUES (47, '中国近代史上签订的第一个不平等条约是？', 1, '《南京条约》', '《北京条约》', '《马关条约》', '《辛丑条约》', 'A', '1842年，清朝在第一次鸦片战争中战败，与英国签订《南京条约》，割让香港岛、赔款2100万银元、开放五口通商，是中国近代史上第一个不平等条约。', 1, '近代史,鸦片战争,南京条约,不平等条约', 1, 2);
INSERT INTO `t_quiz` VALUES (48, '\'罢黜百家，独尊儒术\'是哪位皇帝时期提出的？', 1, '汉高祖', '汉文帝', '汉武帝', '汉光武帝', 'C', '汉武帝时期，董仲舒提出\'罢黜百家，独尊儒术\'的建议，被汉武帝采纳，确立了儒家思想在中国两千多年的正统地位。', 1, '汉朝,汉武帝,董仲舒,儒家思想', 1, 2);
INSERT INTO `t_quiz` VALUES (49, '下列哪些改革措施属于北魏孝文帝改革？', 2, '迁都洛阳', '改汉姓、穿汉服、说汉语', '颁布均田令', '实行科举制', 'ABC', '北魏孝文帝改革（485年起）包括迁都洛阳、汉化政策（改汉姓、穿汉服、说汉语、与汉族通婚）及颁布均田令。科举制创立于隋朝，非孝文帝改革内容。', 3, '北魏,孝文帝改革,民族融合,均田制', 1, 2);
INSERT INTO `t_quiz` VALUES (50, '\'杯酒释兵权\'发生在哪位宋朝皇帝在位时期？', 1, '宋太祖', '宋太宗', '宋仁宗', '宋神宗', 'A', '961年，宋太祖赵匡胤通过酒宴威逼利诱高阶军官交出兵权，成功解除禁军将领兵权，加强中央集权，史称\'杯酒释兵权\'。', 2, '宋朝,赵匡胤,杯酒释兵权,中央集权', 1, 2);
INSERT INTO `t_quiz` VALUES (51, '下列关于辛亥革命的说法，正确的是？', 2, '爆发于1911年10月10日', '推翻了清朝统治，结束了两千多年的封建帝制', '建立了中华民国', '完成了反帝反封建的革命任务', 'ABC', '辛亥革命爆发于1911年武昌起义，推翻清朝、结束帝制、建立民国，具有伟大历史意义。但由于革命果实被袁世凯窃取，未改变中国半殖民地半封建社会性质，反帝反封建任务并未完成。', 3, '近代史,辛亥革命,武昌起义,中华民国', 1, 2);
INSERT INTO `t_quiz` VALUES (52, '被誉为\'史家之绝唱，无韵之离骚\'的史学著作是？', 1, '《左传》', '《史记》', '《汉书》', '《资治通鉴》', 'B', '《史记》是西汉司马迁撰写的中国第一部纪传体通史，记载了从黄帝到汉武帝约3000年历史。鲁迅在《汉文学史纲要》中评价其为\'史家之绝唱，无韵之离骚\'。', 1, '汉朝,司马迁,史记,史学名著', 1, 2);
INSERT INTO `t_quiz` VALUES (53, '中国历史上第一个统一的多民族中央集权国家是？', 1, '夏朝', '商朝', '秦朝', '汉朝', 'C', '公元前221年，秦始皇嬴政灭六国，建立秦朝，是中国历史上第一个统一的多民族中央集权国家，确立了皇帝制度、郡县制等影响深远的制度。', 1, '秦朝,秦始皇,统一六国', 1, 2);
INSERT INTO `t_quiz` VALUES (54, '下列哪些事件发生在唐朝？', 2, '贞观之治', '开元盛世', '安史之乱', '黄巢起义', 'ABCD', '贞观之治是唐太宗时期，开元盛世是唐玄宗前期，安史之乱发生于755-763年，黄巢起义发生于875-884年，均为唐朝重大历史事件。', 2, '唐朝,贞观之治,开元盛世,安史之乱,黄巢起义', 1, 2);
INSERT INTO `t_quiz` VALUES (55, '\'卧薪尝胆\'典故的主人公是？', 1, '夫差', '勾践', '范蠡', '伍子胥', 'B', '春秋时期，越国被吴国打败，越王勾践被迫臣服。他卧薪尝胆、励精图治，最终灭吴复仇，成为春秋最后一位霸主。', 1, '春秋,吴越争霸,勾践,成语典故', 1, 2);
INSERT INTO `t_quiz` VALUES (56, '下列关于汉武帝的措施，说法正确的有？', 2, '采纳董仲舒建议，罢黜百家，独尊儒术', '派遣张骞出使西域，开辟丝绸之路', '颁布推恩令，削弱诸侯王势力', '设立刺史制度，监察地方官员', 'ABCD', '汉武帝刘彻在思想上独尊儒术，外交上派张骞通西域，政治上推恩令削弱诸侯、设刺史监察地方，军事上北击匈奴，是汉朝鼎盛时期。', 2, '汉朝,汉武帝,推恩令,丝绸之路,独尊儒术', 1, 2);
INSERT INTO `t_quiz` VALUES (57, '明朝永乐年间，郑和七次下西洋，其船队最远到达？', 1, '印度半岛', '阿拉伯半岛', '非洲东海岸', '欧洲地中海', 'C', '1405-1433年，郑和七次下西洋，船队规模庞大，最远到达红海沿岸和非洲东海岸（今索马里、肯尼亚一带），是世界航海史上的壮举。', 1, '明朝,郑和,下西洋,航海史', 1, 2);
INSERT INTO `t_quiz` VALUES (58, '\'靖康之变\'中，被金兵俘虏的北宋皇帝是？', 2, '宋太祖赵匡胤', '宋真宗赵恒', '宋徽宗赵佶', '宋钦宗赵桓', 'CD', '1127年，金兵攻破北宋都城开封，俘虏宋徽宗、宋钦宗父子及大量宗室、官员北去，北宋灭亡，史称\'靖康之变\'或\'靖康之耻\'。', 2, '北宋,靖康之变,宋徽宗,宋钦宗,金朝', 1, 2);
INSERT INTO `t_quiz` VALUES (59, '下列改革中，由北魏孝文帝推行的是？', 1, '均田制', '租庸调制', '两税法', '一条鞭法', 'A', '北魏孝文帝拓跋宏（元宏）推行汉化改革，包括迁都洛阳、改汉姓、穿汉服、说汉语、与汉族通婚等，均田制是其重要的经济改革措施。', 3, '北魏,孝文帝改革,均田制,民族融合', 1, 2);
INSERT INTO `t_quiz` VALUES (60, '关于辛亥革命，下列说法正确的有？', 2, '1911年10月10日武昌起义爆发', '孙中山被推举为中华民国临时大总统', '结束了中国两千多年的封建帝制', '完成了反帝反封建的革命任务', 'ABC', '辛亥革命推翻了清朝统治，结束了封建帝制，建立了中华民国，但革命果实被袁世凯窃取，未改变中国半殖民地半封建社会性质，反帝反封建任务未完成。', 2, '辛亥革命,武昌起义,孙中山,中华民国', 1, 2);
INSERT INTO `t_quiz` VALUES (61, '\'焚书坑儒\'中的\'坑儒\'事件，发生在哪位皇帝在位时期？', 1, '秦始皇', '汉武帝', '唐太宗', '明太祖', 'A', '公元前213年和前212年，秦始皇为加强思想控制，采纳李斯建议焚烧诗书、坑杀方士和儒生四百余人，是中国历史上著名的文化专制事件。', 1, '秦朝,秦始皇,焚书坑儒,文化专制', 1, 2);
INSERT INTO `t_quiz` VALUES (62, '下列关于中国近代不平等条约的表述，正确的有？', 2, '《南京条约》是中国近代史上第一个不平等条约', '《马关条约》规定割让台湾全岛及附属岛屿', '《辛丑条约》规定清政府赔款4.5亿两白银', '《天津条约》开放上海为通商口岸', 'ABC', '《南京条约》1842年签订，首开不平等条约先例；《马关条约》1895年割台湾；《辛丑条约》1901年赔款4.5亿两。上海开埠是《南京条约》内容，非《天津条约》。', 3, '近代史,不平等条约,南京条约,马关条约,辛丑条约', 1, 2);
INSERT INTO `t_quiz` VALUES (63, '中国历史上第一个统一的多民族中央集权国家是？', 1, '夏朝', '商朝', '秦朝', '汉朝', 'C', '公元前221年，秦始皇嬴政灭六国，建立秦朝，是中国历史上第一个统一的多民族中央集权国家，确立了皇帝制度、郡县制等重要制度。', 1, '秦朝,统一,秦始皇', 1, 2);
INSERT INTO `t_quiz` VALUES (64, '下列哪些人物属于\"唐宋八大家\"？', 2, '韩愈', '柳宗元', '苏轼', '欧阳修', 'ABCD', '唐宋八大家包括唐代韩愈、柳宗元和宋代欧阳修、苏洵、苏轼、苏辙、王安石、曾巩八位散文家。本题四个选项均为其中人物。', 2, '唐宋八大家,文学,古文运动', 1, 2);
INSERT INTO `t_quiz` VALUES (65, '\"贞观之治\"指的是哪位皇帝在位时期的治世？', 1, '唐太宗李世民', '唐玄宗李隆基', '唐高宗李治', '武则天', 'A', '\"贞观之治\"是唐太宗李世民在位期间（627-649年）出现的政治清明、经济发展、社会安定的治世局面，为后来的开元盛世奠定了基础。', 1, '唐朝,贞观之治,唐太宗', 1, 2);
INSERT INTO `t_quiz` VALUES (66, '郑和下西洋发生在哪个朝代？', 1, '元朝', '明朝', '清朝', '宋朝', 'B', '郑和下西洋是明代永乐、宣德年间（1405-1433年）的一场海上远航活动，郑和率领船队七次远航，到达亚非30多个国家和地区，是世界航海史上的壮举。', 1, '明朝,郑和,航海', 1, 2);
INSERT INTO `t_quiz` VALUES (67, '下列关于鸦片战争的表述，正确的有？', 2, '爆发于1840年', '清政府战败后签订《南京条约》', '是中国近代史的开端', '香港岛在此战后被割让', 'ABCD', '1840年，英国发动鸦片战争，1842年清政府战败签订中国近代史上第一个不平等条约《南京条约》，割让香港岛给英国，开放五口通商，标志着中国近代史的开端。', 2, '鸦片战争,近代史,南京条约', 1, 2);
INSERT INTO `t_quiz` VALUES (68, '\"罢黜百家，独尊儒术\"是谁向汉武帝提出的建议？', 1, '董仲舒', '主父偃', '桑弘羊', '司马迁', 'A', '汉武帝时期，董仲舒提出\"罢黜百家，独尊儒术\"的建议，被汉武帝采纳，使儒家思想成为封建社会的正统思想，影响中国两千余年。', 1, '汉朝,汉武帝,董仲舒,儒家', 1, 2);
INSERT INTO `t_quiz` VALUES (69, '下列关于辛亥革命的说法，正确的有？', 2, '爆发于1911年', '推翻了清朝统治', '结束了中国两千多年的封建帝制', '建立了中华民国', 'ABCD', '1911年10月10日武昌起义爆发，辛亥革命推翻了清王朝统治，结束了中国两千多年的封建君主专制制度，1912年元旦中华民国正式成立。', 2, '辛亥革命,民国,孙中山', 1, 2);
INSERT INTO `t_quiz` VALUES (70, '\"安史之乱\"是唐朝由盛转衰的转折点，其发动者是？', 1, '安禄山、史思明', '安禄山、安庆绪', '史思明、史朝义', '安禄山、朱泚', 'A', '安史之乱是755年至763年唐朝将领安禄山与史思明背叛唐朝后发动的战争，是唐朝由盛而衰的转折点，战乱使北方经济遭到严重破坏。', 1, '唐朝,安史之乱,节度使', 1, 2);
INSERT INTO `t_quiz` VALUES (71, '下列哪些战役属于中国抗日战争时期的重要战役？', 2, '台儿庄大捷', '平型关大捷', '百团大战', '淞沪会战', 'ABCD', '台儿庄大捷（1938年）是抗战以来正面战场最大胜利；平型关大捷（1937年）是八路军出师以来首胜；百团大战（1940年）是敌后战场大规模进攻作战；淞沪会战（1937年）粉碎了日军\"三个月亡华\"计划。', 3, '抗日战争,近代史,重要战役', 1, 2);
INSERT INTO `t_quiz` VALUES (72, '\"靖康之变\"中被金兵俘虏的两位宋朝皇帝是？', 1, '宋徽宗、宋钦宗', '宋仁宗、宋英宗', '宋神宗、宋哲宗', '宋高宗、宋孝宗', 'A', '1127年，金兵攻破北宋都城汴京，俘虏宋徽宗、宋钦宗二帝及大量宗室、官员北去，北宋灭亡，史称\"靖康之变\"或\"靖康之耻\"。', 2, '北宋,靖康之变,金朝,宋徽宗', 1, 2);
INSERT INTO `t_quiz` VALUES (73, '中国历史上第一个统一的多民族中央集权国家是', 1, '夏朝', '商朝', '秦朝', '汉朝', 'C', '公元前221年，秦始皇嬴政灭六国，建立秦朝，是中国历史上第一个统一的多民族中央集权国家。', 1, '秦朝,统一,秦始皇', 1, 2);
INSERT INTO `t_quiz` VALUES (74, '下列哪些人物属于\"唐宋八大家\"', 2, '韩愈', '柳宗元', '苏轼', '王安石', 'ABCD', '唐宋八大家包括唐代的韩愈、柳宗元和宋代的欧阳修、苏洵、苏轼、苏辙、王安石、曾巩。', 2, '唐宋八大家,文学,唐宋', 1, 2);
INSERT INTO `t_quiz` VALUES (75, '明朝永乐年间，郑和七次下西洋，其船队最远到达', 1, '印度半岛', '阿拉伯半岛', '非洲东海岸', '欧洲地中海', 'C', '郑和船队最远到达非洲东海岸的麻林（今肯尼亚马林迪）和木骨都束（今索马里摩加迪沙）。', 1, '明朝,郑和,航海', 1, 2);
INSERT INTO `t_quiz` VALUES (76, '下列关于中国四大发明的说法，正确的是', 2, '东汉蔡伦改进造纸术', '唐朝发明活字印刷术', '火药在唐末开始用于军事', '指南针在宋代应用于航海', 'ACD', '活字印刷术由北宋毕昇发明，而非唐朝。其他三项均正确。', 2, '四大发明,科技,唐宋', 1, 2);
INSERT INTO `t_quiz` VALUES (77, '\"开元盛世\"是下列哪位皇帝在位时期出现的治世', 1, '唐太宗', '唐玄宗', '武则天', '唐高宗', 'B', '唐玄宗李隆基在位前期（开元年间），励精图治，开创了唐朝极盛之世，史称\"开元盛世\"。', 1, '唐朝,开元盛世,唐玄宗', 1, 2);
INSERT INTO `t_quiz` VALUES (78, '1842年，清政府与英国签订的近代中国第一个不平等条约是', 1, '《南京条约》', '《北京条约》', '《马关条约》', '《辛丑条约》', 'A', '《南京条约》是第一次鸦片战争后签订，内容包括割香港岛、赔款2100万银元、开放五口通商等。', 1, '鸦片战争,南京条约,近代史', 1, 2);
INSERT INTO `t_quiz` VALUES (79, '下列战役发生在抗日战争时期的是', 2, '平型关大捷', '台儿庄战役', '百团大战', '淮海战役', 'ABC', '淮海战役是解放战争时期的三大战役之一，其他三项均为抗日战争时期的重要战役。', 2, '抗日战争,战役,近代史', 1, 2);
INSERT INTO `t_quiz` VALUES (80, '\"文景之治\"是指西汉哪两位皇帝统治时期出现的治世', 1, '汉高祖、汉惠帝', '汉文帝、汉景帝', '汉武帝、汉昭帝', '汉宣帝、汉元帝', 'B', '汉文帝刘恒和汉景帝刘启统治时期，推行休养生息政策，社会经济恢复发展，史称\"文景之治\"。', 1, '西汉,文景之治,治世', 1, 2);
INSERT INTO `t_quiz` VALUES (81, '下列关于戊戌变法的说法，正确的是', 2, '发生于1898年', '由康有为、梁启超等人推动', '慈禧太后发动政变导致失败', '变法持续了一百天', 'ABCD', '戊戌变法又称百日维新，1898年由光绪帝支持、康梁等人推动，因慈禧发动戊戌政变而失败。', 3, '戊戌变法,维新,近代史', 1, 2);
INSERT INTO `t_quiz` VALUES (82, '商朝后期，将都城迁到殷（今河南安阳）的国王是', 1, '商汤', '盘庚', '武丁', '纣王', 'B', '盘庚即位后，为摆脱政治危机和自然灾害，迁都于殷，此后商朝又称殷商，都城稳定下来。', 2, '商朝,盘庚迁都,先秦', 1, 2);
INSERT INTO `t_quiz` VALUES (83, '中国历史上第一个统一的多民族中央集权国家是？', 1, '夏朝', '商朝', '秦朝', '汉朝', 'C', '公元前221年，秦始皇嬴政灭六国，建立秦朝，是中国历史上第一个统一的多民族中央集权国家，确立了皇帝制度、郡县制等重要制度。', 1, '秦朝,统一,秦始皇', 1, 2);
INSERT INTO `t_quiz` VALUES (84, '下列哪些人物属于\"唐宋八大家\"？', 2, '韩愈', '柳宗元', '苏轼', '欧阳修', 'ABCD', '唐宋八大家包括唐代韩愈、柳宗元和宋代欧阳修、苏洵、苏轼、苏辙、王安石、曾巩八位散文家。本题四个选项均为其中人物。', 2, '唐宋八大家,文学,古文运动', 1, 2);
INSERT INTO `t_quiz` VALUES (85, '\"贞观之治\"指的是哪位皇帝在位时期的治世？', 1, '唐太宗李世民', '唐玄宗李隆基', '唐高宗李治', '武则天', 'A', '\"贞观之治\"是唐太宗李世民在位期间（627-649年）出现的政治清明、经济发展、社会安定的治世局面，为后来的开元盛世奠定了基础。', 1, '唐朝,贞观之治,唐太宗', 1, 2);
INSERT INTO `t_quiz` VALUES (86, '郑和下西洋发生在哪个朝代？', 1, '元朝', '明朝', '清朝', '宋朝', 'B', '郑和下西洋是明代永乐、宣德年间（1405-1433年）的一场海上远航活动，郑和率领船队七次远航，到达亚非30多个国家和地区，是世界航海史上的壮举。', 1, '明朝,郑和,航海', 1, 2);
INSERT INTO `t_quiz` VALUES (87, '下列关于鸦片战争的表述，正确的有？', 2, '爆发于1840年', '清政府战败后签订《南京条约》', '是中国近代史的开端', '香港岛在此战后被割让', 'ABCD', '1840年，英国发动鸦片战争，1842年清政府战败签订中国近代史上第一个不平等条约《南京条约》，割让香港岛给英国，开放五口通商，标志着中国近代史的开端。', 2, '鸦片战争,近代史,南京条约', 1, 2);
INSERT INTO `t_quiz` VALUES (88, '\"罢黜百家，独尊儒术\"是谁向汉武帝提出的建议？', 1, '董仲舒', '主父偃', '桑弘羊', '司马迁', 'A', '汉武帝时期，董仲舒提出\"罢黜百家，独尊儒术\"的建议，被汉武帝采纳，使儒家思想成为封建社会的正统思想，影响中国两千余年。', 1, '汉朝,汉武帝,董仲舒,儒家', 1, 2);
INSERT INTO `t_quiz` VALUES (89, '下列关于辛亥革命的说法，正确的有？', 2, '爆发于1911年', '推翻了清朝统治', '结束了中国两千多年的封建帝制', '建立了中华民国', 'ABCD', '1911年10月10日武昌起义爆发，辛亥革命推翻了清王朝统治，结束了中国两千多年的封建君主专制制度，1912年元旦中华民国正式成立。', 2, '辛亥革命,民国,孙中山', 1, 2);
INSERT INTO `t_quiz` VALUES (90, '\"安史之乱\"是唐朝由盛转衰的转折点，其发动者是？', 1, '安禄山、史思明', '安禄山、安庆绪', '史思明、史朝义', '安禄山、朱泚', 'A', '安史之乱是755年至763年唐朝将领安禄山与史思明背叛唐朝后发动的战争，是唐朝由盛而衰的转折点，战乱使北方经济遭到严重破坏。', 1, '唐朝,安史之乱,节度使', 1, 2);
INSERT INTO `t_quiz` VALUES (91, '下列哪些战役属于中国抗日战争时期的重要战役？', 2, '台儿庄大捷', '平型关大捷', '百团大战', '淞沪会战', 'ABCD', '台儿庄大捷（1938年）是抗战以来正面战场最大胜利；平型关大捷（1937年）是八路军出师以来首胜；百团大战（1940年）是敌后战场大规模进攻作战；淞沪会战（1937年）粉碎了日军\"三个月亡华\"计划。', 3, '抗日战争,近代史,重要战役', 1, 2);
INSERT INTO `t_quiz` VALUES (92, '\"靖康之变\"中被金兵俘虏的两位宋朝皇帝是？', 1, '宋徽宗、宋钦宗', '宋仁宗、宋英宗', '宋神宗、宋哲宗', '宋高宗、宋孝宗', 'A', '1127年，金兵攻破北宋都城汴京，俘虏宋徽宗、宋钦宗二帝及大量宗室、官员北去，北宋灭亡，史称\"靖康之变\"或\"靖康之耻\"。', 2, '北宋,靖康之变,金朝,宋徽宗', 1, 2);
INSERT INTO `t_quiz` VALUES (93, '中国历史上第一个统一的多民族中央集权国家是？', 1, '夏朝', '商朝', '秦朝', '汉朝', 'C', '公元前221年，秦始皇嬴政灭六国，建立秦朝，是中国历史上第一个统一的多民族中央集权国家，确立了皇帝制度、郡县制等重要制度。', 1, '秦朝,统一,秦始皇', 1, 2);
INSERT INTO `t_quiz` VALUES (94, '下列哪些人物属于\"唐宋八大家\"？', 2, '韩愈', '柳宗元', '苏轼', '欧阳修', 'ABCD', '唐宋八大家是唐代韩愈、柳宗元和宋代欧阳修、苏洵、苏轼、苏辙、王安石、曾巩八位散文家的合称。本题四人全部入选。', 2, '唐宋八大家,文学,散文', 1, 2);
INSERT INTO `t_quiz` VALUES (95, '\"贞观之治\"指的是哪位皇帝在位时期的治世？', 1, '唐高祖李渊', '唐太宗李世民', '唐玄宗李隆基', '唐宪宗李纯', 'B', '贞观是唐太宗李世民的年号（627-649年）。唐太宗吸取隋亡教训，轻徭薄赋、任贤纳谏，开创了政治清明、社会安定的\"贞观之治\"。', 1, '唐朝,贞观之治,唐太宗', 1, 2);
INSERT INTO `t_quiz` VALUES (96, '下列关于郑和下西洋的说法，正确的有？', 2, '发生在明朝永乐年间', '最远到达非洲东海岸和红海沿岸', '主要目的是寻找建文帝下落', '船队规模庞大，每次约两万余人', 'ABD', '郑和下西洋始于1405年，明成祖朱棣时期，非寻找建文帝（此为野史说法），主要目的是宣扬国威、发展朝贡贸易。七次远航最远达东非，船队规模宏大。', 2, '明朝,郑和,航海,外交', 1, 2);
INSERT INTO `t_quiz` VALUES (97, '\"焚书坑儒\"事件发生在哪位统治者时期？', 1, '秦始皇', '汉武帝', '隋炀帝', '明太祖', 'A', '公元前213年和前212年，秦始皇采纳李斯建议，焚烧诗书、坑杀方士儒生，史称\"焚书坑儒\"，是加强思想控制的重大事件。', 1, '秦朝,秦始皇,焚书坑儒,文化政策', 1, 2);
INSERT INTO `t_quiz` VALUES (98, '下列哪些战役属于中国古代以少胜多的著名战例？', 2, '巨鹿之战', '官渡之战', '赤壁之战', '淝水之战', 'ABCD', '巨鹿之战（项羽破秦）、官渡之战（曹操胜袁绍）、赤壁之战（孙刘破曹）、淝水之战（东晋胜前秦）均为中国历史上著名的以少胜多战役。', 2, '战争,以少胜多,军事史,著名战役', 1, 2);
INSERT INTO `t_quiz` VALUES (99, '清朝\"康乾盛世\"包括哪些皇帝在位时期？', 2, '康熙帝', '雍正帝', '乾隆帝', '嘉庆帝', 'ABC', '康乾盛世又称康雍乾盛世，是清朝康熙、雍正、乾隆三朝（1662-1796年）持续百余年的繁荣时期，是中国古代最后一个盛世。', 1, '清朝,康乾盛世,康熙,雍正,乾隆', 1, 2);
INSERT INTO `t_quiz` VALUES (100, '关于中国近代史的开端，下列说法正确的是？', 1, '1840年鸦片战争标志着中国近代史的开端', '1894年甲午战争是中国近代史的开端', '1911年辛亥革命是中国近代史的开端', '1919年五四运动是中国近代史的开端', 'A', '1840年鸦片战争后，中国开始沦为半殖民地半封建社会，社会性质发生根本变化，因此被视为中国近代史的开端。五四运动则是新民主主义革命的开端。', 3, '近代史,鸦片战争,半殖民地半封建社会,历史分期', 1, 2);

-- ----------------------------
-- Table structure for t_search_hot
-- ----------------------------
DROP TABLE IF EXISTS `t_search_hot`;
CREATE TABLE `t_search_hot`  (
  `id` int NOT NULL AUTO_INCREMENT COMMENT '主键',
  `keyword` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '热门关键词',
  `sort_order` int NOT NULL DEFAULT 0 COMMENT '排序权重（越大越靠前）',
  `status` tinyint NOT NULL DEFAULT 1 COMMENT '状态：0=下线，1=展示',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_keyword`(`keyword` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 11 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '搜索热词表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of t_search_hot
-- ----------------------------
INSERT INTO `t_search_hot` VALUES (1, '三国演义', 100, 1);
INSERT INTO `t_search_hot` VALUES (2, '清朝皇帝', 95, 1);
INSERT INTO `t_search_hot` VALUES (4, '丝绸之路', 85, 1);
INSERT INTO `t_search_hot` VALUES (7, '唐朝', 70, 1);
INSERT INTO `t_search_hot` VALUES (8, '明朝', 65, 1);
INSERT INTO `t_search_hot` VALUES (9, '秦始皇', 60, 1);
INSERT INTO `t_search_hot` VALUES (10, '武则天', 55, 1);

-- ----------------------------
-- Table structure for t_user
-- ----------------------------
DROP TABLE IF EXISTS `t_user`;
CREATE TABLE `t_user`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键',
  `username` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '用户名',
  `password` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '密码',
  `phone` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '手机号',
  `avatar` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'https://history-study.oss-cn-beijing.aliyuncs.com/defaultAvatar.png' COMMENT '头像',
  `register_date` date NOT NULL COMMENT '注册日期',
  `streak_days` int NOT NULL DEFAULT 0 COMMENT '当前连续学习天数',
  `max_streak_days` int NOT NULL DEFAULT 0 COMMENT '历史最高连续天数',
  `total_quiz_count` int NOT NULL DEFAULT 0 COMMENT '累计答题总数',
  `correct_quiz_count` int NOT NULL DEFAULT 0 COMMENT '累计答题正确数',
  `total_favorite_count` int NULL DEFAULT 0 COMMENT '累计收藏总数',
  `status` tinyint NOT NULL DEFAULT 1 COMMENT '状态：0=禁用，1=正常',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_username`(`username` ASC) USING BTREE,
  UNIQUE INDEX `uk_phone`(`phone` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 4 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '用户表' ROW_FORMAT = Dynamic;

