  INDEX `idx_user_date`(`user_id` ASC, `answer_date` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 6 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '用户答题记录表' ROW_FORMAT = Dynamic;

